import { useState, useEffect, useLayoutEffect, useRef, useCallback } from "react";
import { createClient } from "@supabase/supabase-js";

// ============================================================
// WHAT THE FUDGE TRIVIA — FUDGE CANDY EDITION
// Full rebrand: emoji fudge candy aesthetic, puffy 3D primary
// buttons, flat cookie secondary buttons, teal accents, WTF logo
// ============================================================

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Fredoka+One&family=Nunito:ital,wght@0,400;0,700;0,800;0,900;1,700&display=swap');

  :root {
    --yellow: #FFE347;
    --yellow-dark: #E6C800;
    --yellow-pale: #FFFBE6;
    --pink: #FF5C8D;
    --pink-dark: #CC3366;
    --pink-light: #FFD6E7;
    --teal: #2DD4BF;
    --teal-dark: #0F9488;
    --teal-light: #CCFBF1;
    --blue: #3B82F6;
    --blue-dark: #1D4ED8;
    --blue-light: #DBEAFE;
    --green: #22C55E;
    --green-dark: #15803D;
    --green-light: #DCFCE7;
    --orange: #FF8C00;
    --orange-dark: #CC6600;
    --red: #EF4444;
    --red-dark: #B91C1C;
    --purple: #A855F7;
    --purple-dark: #7E22CE;
    --white: #FFFEF5;
    --black: #1A1A1A;
    --ink: 3px solid #1A1A1A;
    --ink-thick: 4px solid #1A1A1A;
    --shadow: 5px 5px 0px #1A1A1A;
    --shadow-sm: 3px 3px 0px #1A1A1A;
    --shadow-lg: 7px 7px 0px #1A1A1A;
    --shadow-xl: 10px 10px 0px #1A1A1A;
    --r: 16px;
    --r-sm: 10px;
    --r-pill: 999px;
    /* Fudge puck 3D effect vars */
    --puck-radius: 18px;
  }

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: 'Nunito', sans-serif;
    background: var(--yellow);
    background-image: radial-gradient(circle, #1A1A1A 1.2px, transparent 1.2px);
    background-size: 26px 26px;
    min-height: 100vh;
    overflow-x: hidden;
    cursor: default;
  }

  /* ===== CONFETTI CANVAS ===== */
  #confetti-canvas {
    position: fixed;
    inset: 0;
    pointer-events: none;
    z-index: 9999;
  }

  /* ===== APP SHELL ===== */
  .app {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    background: var(--yellow);
    background-image: radial-gradient(circle, #1A1A1A 1.2px, transparent 1.2px);
    background-size: 26px 26px;
  }

  /* ===== HEADER ===== */
  .hdr {
    width: 100%;
    max-width: 500px;
    padding: 14px 20px 0;
    display: flex;
    align-items: center;
    justify-content: space-between;
  }

  /* ===== WTF LOGO ===== */
  .logo {
    font-family: 'Fredoka One', cursive;
    line-height: 1;
    display: flex;
    flex-direction: column;
    gap: 0px;
  }

  .logo-line1 {
    font-size: 13px;
    letter-spacing: 1px;
    color: var(--black);
    display: flex;
    gap: 3px;
    align-items: baseline;
  }

  .logo-line2 {
    font-size: 26px;
    display: flex;
    align-items: baseline;
    gap: 3px;
    line-height: 1.05;
  }

  .logo-line3 {
    font-size: 13px;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: var(--purple);
    -webkit-text-stroke: 0.5px var(--black);
  }

  .logo-what { color: var(--black); font-size: 13px; }
  .logo-the  { color: var(--teal-dark); font-size: 13px; }

  .logo-fudge {
    color: var(--pink);
    -webkit-text-stroke: 1.5px var(--black);
    font-size: 28px;
    display: inline-block;
    transform: rotate(-2deg);
    text-shadow: 3px 3px 0 var(--pink-dark);
    letter-spacing: -0.5px;
  }

  .logo-emoji {
    font-size: 20px;
    display: inline-block;
    animation: wobble 2.5s ease-in-out infinite;
    -webkit-text-stroke: 0;
    text-shadow: none;
  }

  .logo-trivia {
    color: var(--teal);
    -webkit-text-stroke: 1.5px var(--black);
    font-size: 20px;
    display: inline-block;
    transform: rotate(1.5deg);
    text-shadow: 2px 2px 0 var(--teal-dark);
  }

  .nav-row { display: flex; gap: 6px; align-items: center; }

  /* ===== FLAT COOKIE BUTTON (secondary) ===== */
  .nav-btn {
    font-family: 'Fredoka One', cursive;
    font-size: 13px;
    background: var(--white);
    border: 2.5px solid var(--black);
    border-radius: var(--r-pill);
    padding: 6px 14px;
    cursor: pointer;
    box-shadow: 3px 3px 0 var(--black);
    color: var(--black);
    transition: transform .12s, box-shadow .12s;
    letter-spacing: .3px;
    position: relative;
  }
  .nav-btn::after {
    content: '';
    position: absolute;
    inset: 3px;
    border-radius: var(--r-pill);
    background: linear-gradient(180deg, rgba(255,255,255,.55) 0%, transparent 60%);
    pointer-events: none;
  }
  .nav-btn:hover { transform: translate(-1px,-2px); box-shadow: 4px 5px 0 var(--black); }
  .nav-btn:active { transform: translate(2px,2px); box-shadow: 1px 1px 0 var(--black); }

  /* ===== MAIN ===== */
  .main {
    width: 100%;
    max-width: 500px;
    padding: 10px 16px 32px;
    flex: 1;
    display: flex;
    flex-direction: column;
  }

  /* ===== BASE CARD ===== */
  .card {
    background: var(--white);
    border: var(--ink-thick);
    border-radius: var(--r);
    padding: 24px 20px;
    box-shadow: var(--shadow-lg);
    position: relative;
  }

  /* ===== STREAK / COMBO ===== */
  .streak-row {
    display: flex;
    gap: 8px;
    margin-bottom: 12px;
    flex-wrap: wrap;
  }

  .badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    font-family: 'Fredoka One', cursive;
    font-size: 14px;
    padding: 5px 14px;
    border-radius: var(--r-pill);
    border: 2.5px solid var(--black);
    box-shadow: var(--shadow-sm);
    letter-spacing: .3px;
    position: relative;
  }
  .badge::after {
    content: '';
    position: absolute;
    inset: 3px;
    border-radius: var(--r-pill);
    background: linear-gradient(180deg, rgba(255,255,255,.4) 0%, transparent 55%);
    pointer-events: none;
  }

  .badge-orange { background: var(--orange); color: var(--white); box-shadow: 3px 3px 0 var(--orange-dark); border-color: var(--orange-dark); }
  .badge-purple { background: var(--purple); color: var(--white); box-shadow: 3px 3px 0 var(--purple-dark); border-color: var(--purple-dark); }
  .badge-blue   { background: var(--blue);   color: var(--white); box-shadow: 3px 3px 0 var(--blue-dark); border-color: var(--blue-dark); }
  .badge-teal   { background: var(--teal);   color: var(--black); box-shadow: 3px 3px 0 var(--teal-dark); border-color: var(--teal-dark); }

  /* ===== HOME CARD ===== */
  .theme-lbl {
    font-family: 'Fredoka One', cursive;
    font-size: 12px;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: var(--teal-dark);
    margin-bottom: 5px;
  }

  .theme-title {
    font-family: 'Fredoka One', cursive;
    font-size: 24px;
    color: var(--black);
    line-height: 1.25;
    margin-bottom: 12px;
  }

  .vs-strip {
    display: flex;
    align-items: center;
    gap: 7px;
    margin-bottom: 14px;
    flex-wrap: wrap;
  }

  .cat-chip {
    font-family: 'Fredoka One', cursive;
    font-size: 13px;
    padding: 5px 15px;
    border-radius: var(--r-pill);
    border: 2.5px solid var(--black);
    box-shadow: 3px 3px 0 var(--black);
    position: relative;
    max-width: min(46vw, 220px);
    min-height: 32px;
    box-sizing: border-box;
    overflow: hidden;
    width: fit-content;
    flex: 0 1 auto;
  }
  .cat-chip::after {
    content: '';
    position: absolute;
    inset: 3px;
    border-radius: var(--r-pill);
    background: linear-gradient(180deg, rgba(255,255,255,.45) 0%, transparent 60%);
    pointer-events: none;
  }

  .cat-a { background: var(--teal); color: var(--black); box-shadow: 3px 3px 0 var(--teal-dark); border-color: var(--teal-dark); }
  .cat-b { background: var(--pink); color: white; box-shadow: 3px 3px 0 var(--pink-dark); border-color: var(--pink-dark); }
  .vs-word { font-family: 'Fredoka One', cursive; font-size: 16px; color: var(--orange); transform: rotate(-5deg); display: inline-block; -webkit-text-stroke: 1px var(--black); }

  .theme-count { font-size: 13px; font-weight: 800; color: #666; margin-bottom: 16px; }

  .fit-text-box {
    display: flex;
    align-items: center;
    justify-content: center;
    min-width: 0;
    overflow: hidden;
    text-align: center;
  }
  .fit-text-content {
    display: block;
    max-width: 100%;
    line-height: 1.08;
    overflow-wrap: break-word;
    word-break: normal;
  }
  .fit-text-one-line .fit-text-content {
    white-space: nowrap;
  }

  /* ===== FUDGE PUCK BUTTON (primary) ===== */
  .btn {
    display: block;
    width: 100%;
    font-family: 'Fredoka One', cursive;
    font-size: 20px;
    letter-spacing: .3px;
    padding: 16px 15px 14px;
    border: 3px solid var(--black);
    border-radius: var(--puck-radius);
    cursor: pointer;
    text-align: center;
    color: var(--black);
    line-height: 1;
    position: relative;
    transition: transform .12s, box-shadow .12s;
    /* Puck 3D side */
    box-shadow: 0 6px 0 rgba(0,0,0,0.35), 0 7px 0 rgba(0,0,0,0.15), 3px 9px 0 rgba(0,0,0,0.12);
  }
  /* Shiny top highlight */
  .btn::before {
    content: '';
    position: absolute;
    top: 5px; left: 12px; right: 12px;
    height: 35%;
    border-radius: var(--puck-radius) var(--puck-radius) 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.55) 0%, rgba(255,255,255,.0) 100%);
    pointer-events: none;
  }
  .btn:hover  { transform: translateY(-2px); box-shadow: 0 8px 0 rgba(0,0,0,0.35), 0 10px 0 rgba(0,0,0,0.12), 4px 11px 0 rgba(0,0,0,0.1); }
  .btn:active { transform: translateY(4px);  box-shadow: 0 2px 0 rgba(0,0,0,0.35); }

  .btn-yellow { background: linear-gradient(180deg, #FFF176 0%, #FFE347 50%, #F0D020 100%); }
  .btn-pink   { background: linear-gradient(180deg, #FF85AA 0%, #FF5C8D 50%, #D63870 100%); color: white; }
  .btn-green  { background: linear-gradient(180deg, #4ADE80 0%, #22C55E 50%, #16A34A 100%); color: white; }
  .btn-blue   { background: linear-gradient(180deg, #60A5FA 0%, #3B82F6 50%, #1D4ED8 100%); color: white; }
  .btn-teal   { background: linear-gradient(180deg, #5EEAD4 0%, #2DD4BF 50%, #0F9488 100%); color: var(--black); }
  .btn-orange { background: linear-gradient(180deg, #FB923C 0%, #FF8C00 50%, #CC6600 100%); color: white; }
  .btn-purple { background: linear-gradient(180deg, #C084FC 0%, #A855F7 50%, #7E22CE 100%); color: white; }

  /* ===== FLAT COOKIE BUTTON (secondary/small) ===== */
  .btn-sm {
    font-family: 'Fredoka One', cursive;
    font-size: 14px;
    padding: 9px 18px;
    border: 2.5px solid var(--black);
    border-radius: var(--r-pill);
    cursor: pointer;
    background: var(--white);
    color: var(--black);
    letter-spacing: .2px;
    position: relative;
    transition: transform .12s, box-shadow .12s;
    box-shadow: 3px 3px 0 var(--black);
  }
  .btn-sm::after {
    content: '';
    position: absolute;
    inset: 3px;
    border-radius: var(--r-pill);
    background: linear-gradient(180deg, rgba(255,255,255,.5) 0%, transparent 60%);
    pointer-events: none;
  }
  /* ===== BIG NAV TILES (Stats / Archive) ===== */
  .btn-row { display: flex; gap: 12px; margin-top: 14px; }
  .btn-nav-tile {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: space-between;
    gap: 0;
    padding: 8px 6px 12px;
    border: 3px solid var(--black);
    border-radius: 22px;
    cursor: pointer;
    transition: transform .12s, box-shadow .12s;
    position: relative;
    overflow: hidden;
    color: white;
  }
  .btn-nav-tile::before {
    content: '';
    position: absolute;
    top: 6px; left: 12px; right: 12px;
    height: 26%;
    border-radius: 16px 16px 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.35) 0%, rgba(255,255,255,0) 100%);
    pointer-events: none;
  }
  .btn-nav-tile:hover  { transform: translateY(-3px); }
  .btn-nav-tile:active { transform: translateY(5px); }

  .btn-nav-tile.tile-teal {
    background: var(--teal);
    box-shadow: 0 8px 0 var(--teal-dark), 0 10px 0 rgba(0,0,0,0.12);
    border-color: var(--teal-dark);
  }
  .btn-nav-tile.tile-teal:hover  { box-shadow: 0 11px 0 var(--teal-dark), 0 13px 0 rgba(0,0,0,0.12); }
  .btn-nav-tile.tile-teal:active { box-shadow: 0 2px 0 var(--teal-dark); }

  .btn-nav-tile.tile-orange {
    background: var(--orange);
    box-shadow: 0 8px 0 var(--orange-dark), 0 10px 0 rgba(0,0,0,0.12);
    border-color: var(--orange-dark);
  }
  .btn-nav-tile.tile-orange:hover  { box-shadow: 0 11px 0 var(--orange-dark), 0 13px 0 rgba(0,0,0,0.12); }
  .btn-nav-tile.tile-orange:active { box-shadow: 0 2px 0 var(--orange-dark); }

  .btn-nav-tile-lbl {
    font-family: 'Fredoka One', cursive;
    font-size: 24px;
    letter-spacing: .4px;
    line-height: 1;
    color: white;
    -webkit-text-stroke: 0.5px rgba(0,0,0,0.2);
    text-shadow: 1px 2px 0 rgba(0,0,0,0.15);
  }

  /* Keep old btn-sm for back buttons etc */
  .btn-sm {
    font-family: 'Fredoka One', cursive;
    font-size: 14px;
    padding: 9px 18px;
    border: 2.5px solid var(--black);
    border-radius: var(--r-pill);
    cursor: pointer;
    background: var(--white);
    color: var(--black);
    letter-spacing: .2px;
    position: relative;
    transition: transform .12s, box-shadow .12s;
    box-shadow: 3px 3px 0 var(--black);
  }
  .btn-sm::after {
    content: '';
    position: absolute;
    inset: 3px;
    border-radius: var(--r-pill);
    background: linear-gradient(180deg, rgba(255,255,255,.5) 0%, transparent 60%);
    pointer-events: none;
  }
  .btn-sm:hover  { transform: translate(-1px,-1px); box-shadow: 4px 4px 0 var(--black); }
  .btn-sm:active { transform: translate(2px,2px);   box-shadow: 1px 1px 0 var(--black); }

  /* ===== PROGRESS ===== */
  .prog-wrap {
    background: linear-gradient(160deg, #FFFEF5 0%, #FFF8E7 100%);
    border: 2.5px solid var(--black);
    border-radius: 18px;
    padding: 8px 14px;
    box-shadow: 0 5px 0 rgba(0,0,0,0.14);
    margin-bottom: 8px;
    position: relative;
  }
  .prog-wrap::before {
    content: '';
    position: absolute;
    top: 4px; left: 10px; right: 10px;
    height: 25%;
    border-radius: 12px 12px 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.55) 0%, rgba(255,255,255,0) 100%);
    pointer-events: none;
  }

  .prog-top {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 9px;
  }

  .prog-ql { font-family: 'Fredoka One', cursive; font-size: 15px; color: var(--black); }
  .prog-score { font-family: 'Fredoka One', cursive; font-size: 15px; color: var(--teal-dark); }

  .combo-flash {
    font-family: 'Fredoka One', cursive;
    font-size: 13px;
    color: var(--orange);
    -webkit-text-stroke: 0.3px var(--orange-dark);
    animation: comboAppear .4s cubic-bezier(.34,1.56,.64,1);
  }

  .dots { display: flex; gap: 5px; flex-wrap: wrap; }

  .dot {
    width: 14px; height: 14px;
    border-radius: 50%;
    background: #ddd;
    border: 2px solid rgba(0,0,0,0.2);
    transition: all .25s;
    box-shadow: 0 2px 0 rgba(0,0,0,0.15);
    position: relative;
  }
  .dot::after {
    content: '';
    position: absolute;
    top: 2px; left: 2px;
    width: 5px; height: 4px;
    border-radius: 50%;
    background: rgba(255,255,255,.6);
    pointer-events: none;
  }
  .dot.cur { background: linear-gradient(180deg,#FFF176,#FFE347 60%,#E6C800); border-color: var(--yellow-dark); transform: scale(1.35); animation: dotPulse .7s ease infinite; box-shadow: 0 3px 0 var(--yellow-dark); }
  .dot.ok  { background: linear-gradient(180deg,#4ADE80,#22C55E 60%,#16A34A); border-color: var(--green-dark); box-shadow: 0 2px 0 var(--green-dark); }
  .dot.no  { background: linear-gradient(180deg,#F87171,#EF4444 60%,#B91C1C); border-color: var(--red-dark); box-shadow: 0 2px 0 var(--red-dark); }

  /* ===== QUESTION CARD ===== */
  .q-card {
    background: linear-gradient(160deg, #FFFEF5 0%, #FFF8E7 100%);
    border: 3px solid var(--black);
    border-radius: 24px;
    padding: 18px 20px 16px;
    box-shadow: 0 8px 0 rgba(0,0,0,0.18), 0 10px 0 rgba(0,0,0,0.08);
    position: relative;
  }
  .q-card::before {
    content: '';
    position: absolute;
    top: 6px; left: 14px; right: 14px;
    height: 22%;
    border-radius: 18px 18px 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.6) 0%, rgba(255,255,255,0) 100%);
    pointer-events: none;
  }

  .q-deco {
    position: absolute;
    top: -18px; left: 16px;
    font-family: 'Fredoka One', cursive;
    font-size: 48px;
    color: var(--teal);
    -webkit-text-stroke: 2px var(--black);
    transform: rotate(-10deg);
    pointer-events: none;
    filter: drop-shadow(2px 3px 0 var(--teal-dark));
  }

  .item-text {
    font-family: 'Fredoka One', cursive;
    font-size: 36px;
    color: var(--black);
    text-align: center;
    line-height: 1.15;
    margin-bottom: 0;
    letter-spacing: .3px;
    padding: 8px 0 4px;
  }

  .ans-btns {
    display: flex;
    flex-direction: row;
    gap: 10px;
  }

  /* ===== THUMB-TAP ANSWER BOX — two stacked squares ===== */
  .ans-box {
    flex: 1;
    border: 3px solid var(--black);
    border-radius: 20px;
    overflow: hidden;
    cursor: pointer;
    transition: transform .12s, box-shadow .12s;
    position: relative;
    display: flex;
    flex-direction: column;
    box-shadow: 0 6px 0 rgba(0,0,0,0.25), 0 8px 0 rgba(0,0,0,0.08);
  }
  .ans-box::after {
    content: '';
    position: absolute;
    top: 6px; left: 8px; right: 8px;
    height: 18%;
    border-radius: 14px 14px 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.45) 0%, rgba(255,255,255,0) 100%);
    pointer-events: none;
    z-index: 2;
  }
  .ans-box:hover:not(.dis) { transform: translateY(-3px); box-shadow: 0 9px 0 rgba(0,0,0,0.25), 0 11px 0 rgba(0,0,0,0.08); }
  .ans-box:active:not(.dis) { transform: translateY(4px); box-shadow: 0 2px 0 rgba(0,0,0,0.25); }
  .ans-box.dis { cursor: default; }

  /* Image half — square via aspect-ratio */
  .ans-box-img-wrap {
    width: 100%;
    aspect-ratio: 1;
    overflow: hidden;
    flex-shrink: 0;
    border-bottom: 2.5px solid rgba(0,0,0,0.2);
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .ans-box-img {
    width: 80%;
    height: 80%;
    object-fit: contain;
    display: block;
  }
  .ans-box-img-placeholder {
    width: 100%;
    aspect-ratio: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 52px;
    filter: drop-shadow(0 2px 0 rgba(0,0,0,0.15));
    flex-shrink: 0;
    border-bottom: 2.5px solid rgba(0,0,0,0.15);
  }

  /* Label half — square via aspect-ratio, text fills it */
  .ans-box-label {
    font-family: 'Fredoka One', cursive;
    font-size: clamp(18px, 8vw, 48px);
    color: white;
    text-align: center;
    padding: 6px;
    line-height: 1.1;
    -webkit-text-stroke: 0.5px rgba(0,0,0,0.25);
    text-shadow: 2px 3px 0 rgba(0,0,0,0.2);
    letter-spacing: .2px;
    position: relative;
    z-index: 1;
    width: 100%;
    aspect-ratio: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
  }
  .ans-box.cat-a-box .ans-box-label { color: var(--black); text-shadow: none; -webkit-text-stroke: 0; }

  /* ===== ANSWER BOX COLOR PALETTE (set per-game in admin) ===== */
  /* Correct/wrong: only the label half changes color, image stays untouched */
  .ans-box.correct {
    animation: correctPop .4s cubic-bezier(.34,1.56,.64,1);
    box-shadow: 0 6px 0 var(--green-dark) !important;
    border-color: var(--green-dark) !important;
  }
  .ans-box.wrong {
    animation: wrongShake .4s ease;
    box-shadow: 0 6px 0 var(--red-dark) !important;
    border-color: var(--red-dark) !important;
  }
  .ans-box.correct .ans-box-label {
    background: linear-gradient(160deg, #4ADE80 0%, #22C55E 55%, #16A34A 100%) !important;
    color: white !important;
    text-shadow: 1px 2px 0 rgba(0,0,0,0.2) !important;
    -webkit-text-stroke: 0.5px rgba(0,0,0,0.2) !important;
  }
  .ans-box.wrong .ans-box-label {
    background: linear-gradient(160deg, #F87171 0%, #EF4444 55%, #B91C1C 100%) !important;
    color: white !important;
    text-shadow: 1px 2px 0 rgba(0,0,0,0.2) !important;
    -webkit-text-stroke: 0.5px rgba(0,0,0,0.2) !important;
  }

  /* Keep old ans-btn for beat/reveal fallback compatibility */
  .ans-btn {
    width: 100%;
    padding: 15px 17px;
    border: 3px solid var(--black);
    border-radius: var(--puck-radius);
    background: var(--white);
    font-family: 'Fredoka One', cursive;
    font-size: 17px;
    color: var(--black);
    cursor: pointer;
    text-align: left;
    display: flex;
    align-items: center;
    gap: 11px;
    transition: transform .12s, box-shadow .12s;
    position: relative;
    overflow: hidden;
    letter-spacing: .2px;
    box-shadow: 0 5px 0 rgba(0,0,0,0.28), 0 6px 0 rgba(0,0,0,0.1);
  }
  .ans-btn::before {
    content: '';
    position: absolute;
    top: 4px; left: 10px; right: 10px;
    height: 30%;
    border-radius: var(--puck-radius) var(--puck-radius) 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.5) 0%, rgba(255,255,255,.0) 100%);
    pointer-events: none;
  }
  .ans-btn:hover:not(.dis) { transform: translateY(-2px); box-shadow: 0 7px 0 rgba(0,0,0,0.28); background: #FFFBE0; }
  .ans-btn:active:not(.dis) { transform: translateY(3px); box-shadow: 0 2px 0 rgba(0,0,0,0.28); }
  .ans-btn.dis { cursor: default; }
  .ans-btn.dis:hover { transform: none; }

  .ans-btn.correct {
    background: linear-gradient(180deg, #4ADE80 0%, #22C55E 55%, #16A34A 100%);
    color: white;
    border-color: var(--green-dark);
    box-shadow: 0 5px 0 var(--green-dark);
    animation: correctPop .4s cubic-bezier(.34,1.56,.64,1);
  }

  .ans-btn.wrong {
    background: linear-gradient(180deg, #F87171 0%, #EF4444 55%, #B91C1C 100%);
    color: white;
    border-color: var(--red-dark);
    box-shadow: 0 5px 0 var(--red-dark);
    animation: wrongShake .4s ease;
  }

  .ans-letter {
    width: 30px; height: 30px;
    border-radius: 50%;
    background: linear-gradient(180deg, #5EEAD4 0%, #2DD4BF 60%, #0F9488 100%);
    border: 2.5px solid var(--black);
    display: flex; align-items: center; justify-content: center;
    font-size: 15px;
    font-family: 'Fredoka One', cursive;
    flex-shrink: 0;
    color: var(--black);
    transition: all .15s;
    box-shadow: 0 3px 0 var(--teal-dark);
  }

  .ans-btn.correct .ans-letter { background: rgba(255,255,255,.3); border-color: rgba(255,255,255,.5); color: white; }
  .ans-btn.wrong .ans-letter { background: rgba(255,255,255,.3); border-color: rgba(255,255,255,.5); color: white; }

  /* ===== REACTION OVERLAY ===== */
  .reaction-overlay {
    position: fixed;
    inset: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    pointer-events: none;
    z-index: 500;
  }

  .reaction-bubble {
    font-family: 'Fredoka One', cursive;
    font-size: 88px;
    -webkit-text-stroke: 3px var(--black);
    text-shadow: 5px 5px 0 var(--black);
    animation: reactionBoom .7s cubic-bezier(.34,1.56,.64,1) forwards;
    display: inline-block;
  }

  /* ===== BEAT — dramatic emoji pop, no "loading" text ===== */
  .beat-overlay {
    position: fixed;
    inset: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    pointer-events: none;
    z-index: 600;
  }
  .beat-emoji-pop {
    font-size: 120px;
    display: inline-block;
    animation: beatPop .55s cubic-bezier(.34,1.56,.64,1) forwards;
    filter: drop-shadow(0 8px 0 rgba(0,0,0,0.2));
  }
  @keyframes beatPop {
    0%   { transform: scale(0) rotate(-15deg); opacity: 0; }
    55%  { transform: scale(1.2) rotate(8deg);  opacity: 1; }
    80%  { transform: scale(1.05) rotate(-3deg); opacity: 1; }
    100% { transform: scale(0.9) rotate(0deg);  opacity: 0; }
  }

  /* ===== REVEAL — 60% image / 40% text, no scroll ===== */
  .reveal-card {
    background: linear-gradient(160deg, #FFFEF5 0%, #FFF8E7 100%);
    border: 3px solid var(--black);
    border-radius: 24px;
    overflow: hidden;
    box-shadow: 0 8px 0 rgba(0,0,0,0.18), 0 10px 0 rgba(0,0,0,0.08);
    animation: cardSlideUp .35s cubic-bezier(.34,1.4,.64,1);
    position: relative;
    display: flex;
    flex-direction: column;
  }

  /* Big image zone — 60% */
  .reveal-img-zone {
    width: 100%;
    aspect-ratio: 4/3;
    overflow: hidden;
    position: relative;
    flex-shrink: 0;
  }
  .reveal-img {
    width: 100%;
    height: 100%;
    object-fit: contain;
    display: block;
    background: #1A1A1A;
  }
  .reveal-img-overlay {
    position: absolute;
    bottom: 0; left: 0; right: 0;
    background: linear-gradient(0deg, rgba(0,0,0,0.55) 0%, transparent 100%);
    padding: 10px 14px 8px;
  }
  .reveal-video {
    width: 100%;
    height: 100%;
    border: 0;
    display: block;
    background: #1A1A1A;
  }

  /* No-image placeholder */
  .reveal-placeholder {
    width: 100%;
    aspect-ratio: 4/3;
    background: linear-gradient(135deg, var(--teal-light) 0%, var(--yellow-pale) 100%);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 64px;
    flex-shrink: 0;
    border-bottom: 3px solid var(--black);
  }

  /* Text zone — below image */
  .reveal-text-zone {
    padding: 12px 14px 10px;
    display: flex;
    flex-direction: column;
    gap: 7px;
  }

  .verdict-bar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 14px;
    border: 3px solid var(--black);
    border-radius: 14px;
    font-family: 'Fredoka One', cursive;
    font-size: 18px;
    position: relative;
    flex-shrink: 0;
  }
  .verdict-bar::before {
    content: '';
    position: absolute;
    top: 4px; left: 10px; right: 10px;
    height: 30%;
    border-radius: 10px 10px 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.45) 0%, rgba(255,255,255,0) 100%);
    pointer-events: none;
  }
  .verdict-bar.ok { background: linear-gradient(180deg,#4ADE80,#22C55E 55%,#16A34A); color: white; box-shadow: 0 4px 0 var(--green-dark); border-color: var(--green-dark); }
  .verdict-bar.no { background: linear-gradient(180deg,#F87171,#EF4444 55%,#B91C1C); color: white; box-shadow: 0 4px 0 var(--red-dark); border-color: var(--red-dark); }

  .reveal-answer {
    font-family: 'Fredoka One', cursive;
    font-size: 14px;
    color: var(--teal-dark);
    background: linear-gradient(160deg, var(--teal-light) 0%, #A7F3D0 100%);
    border: 2px solid var(--teal-dark);
    border-radius: 10px;
    padding: 4px 12px;
    display: inline-block;
    box-shadow: 0 2px 0 var(--teal-dark);
    position: relative;
    align-self: flex-start;
  }
  .reveal-answer::before {
    content: '';
    position: absolute;
    top: 3px; left: 8px; right: 8px;
    height: 30%;
    border-radius: 6px 6px 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.5) 0%, rgba(255,255,255,0) 100%);
    pointer-events: none;
  }

  .img-source { font-size: 10px; color: #888; text-align: right; font-weight: 700; }

  .flavor-box {
    background: linear-gradient(160deg, #FFFBE6 0%, #FFF3C0 100%);
    border: 2px dashed var(--yellow-dark);
    border-radius: 10px;
    padding: 7px 11px;
    font-size: 13px;
    font-weight: 800;
    font-style: italic;
    color: var(--black);
    line-height: 1.35;
  }

  .expl-box {
    font-size: 12px;
    font-weight: 700;
    color: #555;
    line-height: 1.4;
    padding-top: 6px;
    border-top: 2px dashed #ddd;
  }

  /* ===== SCORE / PERFECT ===== */
  .score-card {
    background: linear-gradient(160deg, #FFFEF5 0%, #FFF8E7 100%);
    border: 3px solid var(--black);
    border-radius: 24px;
    padding: 26px 20px;
    box-shadow: 0 8px 0 rgba(0,0,0,0.18), 0 10px 0 rgba(0,0,0,0.08);
    text-align: center;
    animation: cardSlideUp .45s cubic-bezier(.34,1.3,.64,1);
    position: relative;
    overflow: hidden;
  }
  .score-card::before {
    content: '';
    position: absolute;
    top: 6px; left: 14px; right: 14px;
    height: 16%;
    border-radius: 18px 18px 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.6) 0%, rgba(255,255,255,0) 100%);
    pointer-events: none;
  }

  .score-theme-tag {
    display: inline-block;
    background: linear-gradient(180deg, #5EEAD4 0%, #2DD4BF 55%, #0F9488 100%);
    border: 2.5px solid var(--teal-dark);
    border-radius: var(--r-pill);
    padding: 5px 16px;
    font-family: 'Fredoka One', cursive;
    font-size: 13px;
    box-shadow: 0 3px 0 var(--teal-dark);
    margin-bottom: 14px;
    color: var(--black);
    position: relative;
  }
  .score-theme-tag::after {
    content: '';
    position: absolute;
    inset: 3px;
    border-radius: var(--r-pill);
    background: linear-gradient(180deg, rgba(255,255,255,.45) 0%, transparent 60%);
    pointer-events: none;
  }

  .score-big {
    font-family: 'Fredoka One', cursive;
    font-size: 86px;
    line-height: 1;
    color: var(--pink);
    -webkit-text-stroke: 3px var(--black);
    text-shadow: 4px 4px 0 var(--pink-dark);
    display: block;
    margin-bottom: 2px;
  }

  .score-denom { font-size: 38px; color: var(--black); -webkit-text-stroke: 1.5px var(--black); }
  .score-sublbl { font-family: 'Fredoka One', cursive; font-size: 15px; color: #888; margin-bottom: 6px; }
  .score-msg { font-size: 15px; font-weight: 800; font-style: italic; color: var(--black); margin-bottom: 16px; line-height: 1.5; }

  .emoji-grid { display: flex; gap: 8px; flex-wrap: wrap; justify-content: center; margin: 16px 0; padding: 10px 4px 6px; }
  .emoji-cell {
    width: 28px; height: 28px;
    border-radius: 50%;
    display: inline-block;
    animation: popIn .4s cubic-bezier(.34,1.56,.64,1) backwards;
    position: relative;
    border: 2.5px solid rgba(0,0,0,0.25);
    flex-shrink: 0;
  }
  .emoji-cell.correct-dot {
    background: linear-gradient(160deg, #4ADE80 0%, #22C55E 55%, #16A34A 100%);
    box-shadow: 0 5px 0 #15803D, 0 6px 0 rgba(0,0,0,0.15);
    border-color: #15803D;
  }
  .emoji-cell.wrong-dot {
    background: linear-gradient(160deg, #F87171 0%, #EF4444 55%, #B91C1C 100%);
    box-shadow: 0 5px 0 #B91C1C, 0 6px 0 rgba(0,0,0,0.15);
    border-color: #B91C1C;
  }
  .emoji-cell::after {
    content: '';
    position: absolute;
    top: 3px; left: 5px;
    width: 10px; height: 7px;
    border-radius: 50%;
    background: rgba(255,255,255,0.45);
    pointer-events: none;
  }

  .share-box {
    background: linear-gradient(160deg, #F0FDFB 0%, #CCFBF1 100%);
    border: 2px dashed var(--teal-dark);
    border-radius: 14px;
    padding: 13px;
    font-size: 13px;
    color: var(--black);
    line-height: 1.7;
    font-weight: 700;
    margin-bottom: 14px;
    font-family: monospace;
    white-space: pre-wrap;
    text-align: left;
  }

  /* Perfect score celebration */
  .perfect-banner {
    background: linear-gradient(135deg, #FFF176, #FFE347 40%, #FB923C 100%);
    border: 3px solid var(--black);
    border-radius: 18px;
    padding: 14px;
    margin-bottom: 14px;
    box-shadow: 0 6px 0 var(--orange-dark);
    animation: shinePulse 1.5s ease infinite;
    position: relative;
  }
  .perfect-banner::before {
    content: '';
    position: absolute;
    top: 5px; left: 12px; right: 12px;
    height: 30%;
    border-radius: 12px 12px 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.5) 0%, rgba(255,255,255,0) 100%);
    pointer-events: none;
  }

  .perfect-title {
    font-family: 'Fredoka One', cursive;
    font-size: 28px;
    color: white;
    -webkit-text-stroke: 1px var(--black);
    text-shadow: 3px 3px 0 var(--black);
    margin-bottom: 4px;
  }

  .perfect-sub { font-size: 14px; font-weight: 800; color: rgba(255,255,255,.9); }

  .results-jazz {
    margin: 14px 0 18px;
    display: grid;
    gap: 10px;
  }

  .results-marquee {
    background: linear-gradient(135deg, #FF8C00 0%, #FFE347 40%, #FF5C8D 100%);
    border: 3px solid var(--black);
    border-radius: 18px;
    box-shadow: 0 6px 0 rgba(0,0,0,0.22);
    padding: 12px 14px;
    position: relative;
    overflow: hidden;
  }
  .results-marquee::before {
    content: '';
    position: absolute;
    inset: 4px;
    border-radius: 13px;
    background:
      radial-gradient(circle at 12% 30%, rgba(255,255,255,.55) 0 10px, transparent 11px),
      radial-gradient(circle at 84% 26%, rgba(255,255,255,.45) 0 7px, transparent 8px),
      linear-gradient(180deg, rgba(255,255,255,.28) 0%, rgba(255,255,255,0) 70%);
    pointer-events: none;
  }
  .results-marquee-top {
    font-family: 'Fredoka One', cursive;
    font-size: 12px;
    letter-spacing: 1.8px;
    text-transform: uppercase;
    color: rgba(26,26,26,.75);
    margin-bottom: 4px;
    position: relative;
    z-index: 1;
  }
  .results-marquee-main {
    font-family: 'Fredoka One', cursive;
    font-size: 22px;
    line-height: 1.08;
    color: white;
    -webkit-text-stroke: 1.2px var(--black);
    text-shadow: 3px 3px 0 rgba(0,0,0,.24);
    position: relative;
    z-index: 1;
  }

  .crowd-wrap {
    margin-top: 14px;
    background: linear-gradient(160deg, #FFF6D9 0%, #FFE8F2 52%, #E6FFFB 100%);
    border: 3px solid var(--black);
    border-radius: 22px;
    padding: 14px;
    box-shadow: 0 6px 0 rgba(0,0,0,0.16);
    position: relative;
    overflow: hidden;
  }
  .crowd-wrap::before {
    content: '';
    position: absolute;
    top: 4px; left: 12px; right: 12px;
    height: 26%;
    border-radius: 18px 18px 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.52) 0%, rgba(255,255,255,0) 100%);
    pointer-events: none;
  }
  .crowd-head {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 8px;
    margin-bottom: 10px;
    position: relative;
    z-index: 1;
  }
  .crowd-title {
    font-family: 'Fredoka One', cursive;
    font-size: 18px;
    color: var(--black);
    text-align: left;
  }
  .crowd-chip {
    font-family: 'Fredoka One', cursive;
    font-size: 11px;
    letter-spacing: .8px;
    text-transform: uppercase;
    color: var(--black);
    padding: 4px 10px;
    border-radius: var(--r-pill);
    border: 2px solid var(--black);
    background: linear-gradient(180deg, #FFF176 0%, #FFE347 55%, #E6C800 100%);
    box-shadow: 0 3px 0 rgba(0,0,0,.2);
    white-space: nowrap;
  }
  .crowd-warning {
    font-size: 12px;
    font-weight: 900;
    color: var(--teal-dark);
    margin-bottom: 10px;
    background: rgba(255,255,255,.55);
    border: 2px dashed rgba(15,148,136,.45);
    border-radius: 14px;
    padding: 8px 10px;
    text-align: left;
    position: relative;
    z-index: 1;
  }
  .crowd-grid {
    display: grid;
    grid-template-columns: 1fr;
    gap: 10px;
    position: relative;
    z-index: 1;
  }
  .crowd-stat {
    border: 3px solid var(--black);
    border-radius: 18px;
    padding: 12px 12px 10px;
    box-shadow: 0 5px 0 rgba(0,0,0,.16);
    text-align: left;
    position: relative;
    overflow: hidden;
  }
  .crowd-stat::before {
    content: '';
    position: absolute;
    top: 4px; left: 10px; right: 10px;
    height: 32%;
    border-radius: 12px 12px 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.4) 0%, rgba(255,255,255,0) 100%);
    pointer-events: none;
  }
  .crowd-stat-avg { background: linear-gradient(160deg, #5EEAD4 0%, #2DD4BF 55%, #0F9488 100%); border-color: var(--teal-dark); }
  .crowd-stat-beat { background: linear-gradient(160deg, #FF85AA 0%, #FF5C8D 55%, #CC3366 100%); border-color: var(--pink-dark); }
  .crowd-stat-perfect { background: linear-gradient(160deg, #FFF176 0%, #FFE347 55%, #FB923C 100%); border-color: var(--orange-dark); }
  .crowd-stat-kicker {
    font-family: 'Fredoka One', cursive;
    font-size: 11px;
    letter-spacing: 1px;
    text-transform: uppercase;
    margin-bottom: 4px;
    position: relative;
    z-index: 1;
  }
  .crowd-stat-avg .crowd-stat-kicker,
  .crowd-stat-beat .crowd-stat-kicker { color: rgba(255,255,255,.82); }
  .crowd-stat-perfect .crowd-stat-kicker { color: rgba(26,26,26,.62); }
  .crowd-stat-main {
    font-family: 'Fredoka One', cursive;
    font-size: 20px;
    line-height: 1.12;
    position: relative;
    z-index: 1;
  }
  .crowd-stat-avg .crowd-stat-main,
  .crowd-stat-beat .crowd-stat-main {
    color: white;
    text-shadow: 2px 2px 0 rgba(0,0,0,.2);
  }
  .crowd-stat-perfect .crowd-stat-main { color: var(--black); }
  .crowd-foot {
    margin-top: 10px;
    font-size: 12px;
    font-weight: 900;
    color: rgba(26,26,26,.66);
    text-align: center;
    position: relative;
    z-index: 1;
  }
  .advanced-toggle {
    margin-top: 12px;
    width: 100%;
  }
  .advanced-panel {
    margin-top: 10px;
    display: grid;
    gap: 8px;
    position: relative;
    z-index: 1;
  }
  .advanced-card {
    background: linear-gradient(160deg, rgba(255,255,255,.88) 0%, rgba(255,255,255,.72) 100%);
    border: 3px solid rgba(26,26,26,.15);
    border-radius: 16px;
    padding: 10px 12px;
    text-align: left;
    box-shadow: 0 4px 0 rgba(0,0,0,.08);
  }
  .advanced-card-top {
    font-family: 'Fredoka One', cursive;
    font-size: 12px;
    color: var(--purple-dark);
    text-transform: uppercase;
    letter-spacing: .6px;
  }
  .advanced-card-title {
    font-size: 14px;
    font-weight: 900;
    color: var(--black);
    margin-top: 2px;
  }
  .advanced-card-sub {
    font-size: 13px;
    font-weight: 800;
    color: rgba(26,26,26,.72);
    margin-top: 4px;
  }

  /* ===== COUNTDOWN ===== */
  .cdown-box {
    margin-top: 16px;
    background: linear-gradient(160deg, #1A1A2E 0%, #1A1A1A 100%);
    border-radius: 18px;
    padding: 14px;
    border: 3px solid var(--black);
    box-shadow: 0 5px 0 rgba(0,0,0,0.4);
    position: relative;
  }
  .cdown-box::before {
    content: '';
    position: absolute;
    top: 5px; left: 12px; right: 12px;
    height: 25%;
    border-radius: 12px 12px 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.08) 0%, rgba(255,255,255,0) 100%);
    pointer-events: none;
  }
  .cdown-lbl { font-family: 'Fredoka One', cursive; font-size: 12px; color: var(--teal); letter-spacing: 2px; text-transform: uppercase; margin-bottom: 3px; }
  .cdown-time { font-family: 'Fredoka One', cursive; font-size: 34px; color: white; letter-spacing: 3px; text-shadow: 0 0 20px rgba(45,212,191,0.4); }

  /* ===== STATS ===== */
  .stats-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-top: 14px; }

  .stat-tile {
    border: 3px solid var(--black);
    border-radius: 20px;
    padding: 15px;
    text-align: center;
    position: relative;
    overflow: hidden;
  }
  .stat-tile::before {
    content: '';
    position: absolute;
    top: 5px; left: 10px; right: 10px;
    height: 28%;
    border-radius: 12px 12px 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.55) 0%, rgba(255,255,255,0) 100%);
    pointer-events: none;
  }

  .stat-tile:nth-child(1) { background: linear-gradient(160deg,#FFF176,#FFE347 55%,#F0D020); box-shadow: 0 5px 0 var(--yellow-dark); }
  .stat-tile:nth-child(2) { background: linear-gradient(160deg,#FF85AA,#FF5C8D 55%,#CC3366); box-shadow: 0 5px 0 var(--pink-dark); }
  .stat-tile:nth-child(3) { background: linear-gradient(160deg,#5EEAD4,#2DD4BF 55%,#0F9488); box-shadow: 0 5px 0 var(--teal-dark); }
  .stat-tile:nth-child(4) { background: linear-gradient(160deg,#C084FC,#A855F7 55%,#7E22CE); box-shadow: 0 5px 0 var(--purple-dark); }
  .stat-tile:nth-child(5) { background: linear-gradient(160deg,#4ADE80,#22C55E 55%,#16A34A); grid-column: span 2; box-shadow: 0 5px 0 var(--green-dark); }

  .stat-val { font-family: 'Fredoka One', cursive; font-size: 40px; color: var(--black); line-height: 1; }
  .stat-tile:nth-child(2) .stat-val,
  .stat-tile:nth-child(4) .stat-val,
  .stat-tile:nth-child(5) .stat-val { color: white; text-shadow: 1px 1px 0 rgba(0,0,0,0.2); }
  .stat-lbl { font-size: 11px; font-weight: 800; color: rgba(0,0,0,0.45); text-transform: uppercase; letter-spacing: .7px; margin-top: 3px; }
  .stat-tile:nth-child(2) .stat-lbl,
  .stat-tile:nth-child(4) .stat-lbl,
  .stat-tile:nth-child(5) .stat-lbl { color: rgba(255,255,255,0.75); }

  /* ===== ARCHIVE ===== */
  .archive-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 11px 8px;
    border-bottom: 2px dashed rgba(45,212,191,0.25);
    cursor: pointer;
    transition: background .15s, transform .1s;
    border-radius: 12px;
    margin: 0 -6px;
    gap: 8px;
  }
  .archive-row:last-child { border-bottom: none; }
  .archive-row:hover { background: linear-gradient(160deg, var(--teal-light) 0%, #FFFBE6 100%); transform: translateX(2px); }
  .archive-row.today-row { background: linear-gradient(160deg, #FFF9E0 0%, #FFFBE6 100%); }

  .archive-date { font-size: 11px; font-weight: 800; color: var(--teal-dark); text-transform: uppercase; letter-spacing: .5px; margin-bottom: 1px; }
  .archive-theme { font-family: 'Fredoka One', cursive; font-size: 14px; color: var(--black); line-height: 1.3; }

  .archive-right { display: flex; align-items: center; gap: 7px; flex-shrink: 0; margin-left: 8px; }

  .score-pill {
    font-family: 'Fredoka One', cursive;
    font-size: 13px;
    padding: 4px 12px;
    border-radius: var(--r-pill);
    border: 2px solid var(--black);
    background: linear-gradient(180deg, #FFF176 0%, #FFE347 55%, #E6C800 100%);
    box-shadow: 0 3px 0 rgba(0,0,0,0.25);
    position: relative;
  }
  .score-pill::after {
    content:''; position:absolute; inset:3px; border-radius:var(--r-pill);
    background:linear-gradient(180deg,rgba(255,255,255,.45) 0%,transparent 60%);
    pointer-events:none;
  }

  .score-pill.perfect { background: linear-gradient(180deg, #4ADE80 0%, #22C55E 55%, #16A34A 100%); color: white; border-color: var(--green-dark); }

  .replay-chip {
    font-family: 'Fredoka One', cursive;
    font-size: 12px;
    padding: 3px 10px;
    border-radius: var(--r-pill);
    border: 2px solid var(--teal-dark);
    background: linear-gradient(180deg, #5EEAD4 0%, #2DD4BF 55%, #0F9488 100%);
    color: var(--black);
    box-shadow: 0 3px 0 var(--teal-dark);
    position: relative;
  }
  .replay-chip::after {
    content:''; position:absolute; inset:2px; border-radius:var(--r-pill);
    background:linear-gradient(180deg,rgba(255,255,255,.4) 0%,transparent 60%);
    pointer-events:none;
  }

  .today-chip {
    font-family: 'Fredoka One', cursive;
    font-size: 12px;
    padding: 3px 10px;
    border-radius: var(--r-pill);
    border: 2px solid var(--orange-dark);
    background: linear-gradient(180deg, #FB923C 0%, #FF8C00 55%, #CC6600 100%);
    color: white;
    box-shadow: 0 3px 0 var(--orange-dark);
    position: relative;
  }
  .today-chip::after {
    content:''; position:absolute; inset:2px; border-radius:var(--r-pill);
    background:linear-gradient(180deg,rgba(255,255,255,.35) 0%,transparent 60%);
    pointer-events:none;
  }

  .replay-banner {
    background: linear-gradient(160deg,#5EEAD4,#2DD4BF 55%,#0F9488);
    color: var(--black);
    font-family: 'Fredoka One', cursive;
    font-size: 14px;
    padding: 10px 16px;
    border-radius: 16px;
    border: 2.5px solid var(--teal-dark);
    box-shadow: 0 4px 0 var(--teal-dark);
    margin-bottom: 12px;
    display: flex;
    align-items: center;
    gap: 8px;
    position: relative;
  }
  .replay-banner::before {
    content: '';
    position: absolute;
    top: 4px; left: 10px; right: 10px;
    height: 30%;
    border-radius: 10px 10px 50% 50%;
    background: linear-gradient(180deg, rgba(255,255,255,.4) 0%, rgba(255,255,255,0) 100%);
    pointer-events: none;
  }

  /* ===== SECTION HEADER ===== */
  .sec-head { font-family: 'Fredoka One', cursive; font-size: 26px; color: var(--black); margin-bottom: 3px; }
  .sec-sub { font-size: 13px; font-weight: 700; color: var(--teal-dark); margin-bottom: 14px; }

  /* ===== ADMIN — upgraded header ===== */
  .adm-shell { background: #0E0E16; min-height: 100vh; font-family: 'Nunito', sans-serif; color: white; }
  .adm-hdr { background: linear-gradient(160deg,#FFF176,#FFE347 55%,#F0D020); border-bottom: 3px solid var(--black); padding: 13px 22px; display: flex; align-items: center; justify-content: space-between; box-shadow: 0 4px 0 rgba(0,0,0,0.15); }
  .adm-title { font-family: 'Fredoka One', cursive; font-size: 20px; color: var(--black); -webkit-text-stroke: 0.3px var(--black); }
  .adm-body { max-width: 820px; margin: 0 auto; padding: 16px 18px; }

  .adm-card { background: #1A1A28; border: 1.5px solid rgba(45,212,191,0.15); border-radius: 18px; padding: 16px; margin-bottom: 12px; }
  .adm-card h3 { font-family: 'Fredoka One', cursive; font-size: 16px; color: var(--teal); margin-bottom: 10px; letter-spacing: .3px; }

  .adm-field { margin-bottom: 9px; }
  .adm-field label { display: block; font-size: 10px; font-weight: 800; letter-spacing: 1px; text-transform: uppercase; color: rgba(45,212,191,.5); margin-bottom: 3px; }

  .adm-input {
    width: 100%;
    background: #12121E;
    border: 1.5px solid rgba(45,212,191,.2);
    border-radius: 12px;
    color: white;
    font-family: 'Nunito', sans-serif;
    font-size: 14px;
    font-weight: 600;
    padding: 8px 11px;
    outline: none;
    transition: border-color .15s;
  }
  .adm-input:focus { border-color: var(--teal); box-shadow: 0 0 0 3px rgba(45,212,191,0.1); }
  .adm-input::placeholder { color: rgba(255,255,255,.18); }
  select.adm-input option { background: #12121E; }
  .adm-ta { resize: vertical; min-height: 64px; }

  .admin-date-picker { margin-bottom: 14px; }
  .admin-date-top { display: flex; gap: 8px; align-items: stretch; }
  .admin-date-input-wrap { flex: 1; }
  .admin-date-btn {
    flex-shrink: 0;
    min-width: 118px;
    background: linear-gradient(180deg,#5EEAD4,#2DD4BF 60%,#0F9488);
    color: var(--black);
    border-color: var(--teal-dark);
    box-shadow: 0 3px 0 var(--teal-dark);
  }
  .admin-date-note {
    margin-top: 7px;
    font-size: 12px;
    font-weight: 800;
    color: rgba(255,255,255,.45);
  }
  .admin-date-note.bad { color: #FCA5A5; }
  .admin-date-note.good { color: #86EFAC; }
  .admin-calendar {
    margin-top: 10px;
    background: #12121E;
    border: 1.5px solid rgba(45,212,191,.22);
    border-radius: 16px;
    padding: 12px;
    box-shadow: inset 0 0 0 1px rgba(255,255,255,.03);
  }
  .admin-cal-head {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 10px;
    margin-bottom: 10px;
  }
  .admin-cal-title {
    font-family: 'Fredoka One', cursive;
    font-size: 16px;
    color: var(--teal);
  }
  .admin-cal-nav { display: flex; gap: 6px; }
  .admin-cal-nav button {
    min-width: 34px;
    height: 30px;
    padding: 0 9px;
    border-radius: 10px;
    border: 1.5px solid rgba(45,212,191,.28);
    background: rgba(45,212,191,.08);
    color: var(--teal);
    font-family: 'Fredoka One', cursive;
    cursor: pointer;
  }
  .admin-cal-grid {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 6px;
  }
  .admin-cal-dow {
    text-align: center;
    color: rgba(45,212,191,.5);
    font-size: 10px;
    font-weight: 900;
    letter-spacing: .7px;
    text-transform: uppercase;
    padding: 2px 0;
  }
  .admin-cal-day {
    min-height: 48px;
    border-radius: 12px;
    border: 1.5px solid rgba(255,255,255,.08);
    background: rgba(255,255,255,.035);
    color: rgba(255,255,255,.75);
    font-weight: 900;
    cursor: pointer;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 3px;
    position: relative;
  }
  .admin-cal-day:hover:not(.empty):not(.occupied) {
    border-color: var(--teal);
    background: rgba(45,212,191,.12);
  }
  .admin-cal-day.empty { visibility: hidden; cursor: default; }
  .admin-cal-day.selected {
    background: linear-gradient(180deg,#FFF176,#FFE347 60%,#E6C800);
    color: var(--black);
    border-color: #B8A000;
    box-shadow: 0 3px 0 #8A7800;
  }
  .admin-cal-day.occupied {
    background: rgba(239,68,68,.14);
    border-color: rgba(239,68,68,.42);
    color: #FCA5A5;
    cursor: not-allowed;
  }
  .admin-cal-day.own {
    background: rgba(45,212,191,.14);
    border-color: rgba(45,212,191,.35);
    color: var(--teal);
    cursor: pointer;
  }
  .admin-cal-day.own.selected {
    background: linear-gradient(180deg,#5EEAD4,#2DD4BF 60%,#0F9488);
    color: var(--black);
    border-color: var(--teal-dark);
  }
  .admin-cal-status {
    font-size: 8px;
    line-height: 1;
    font-weight: 900;
    text-transform: uppercase;
    letter-spacing: .4px;
    opacity: .9;
  }
  .admin-cal-legend {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    margin-top: 10px;
    font-size: 11px;
    color: rgba(255,255,255,.45);
    font-weight: 800;
  }
  .admin-cal-dot {
    width: 9px;
    height: 9px;
    border-radius: 50%;
    display: inline-block;
    margin-right: 5px;
  }
  .admin-cal-dot.used { background: #EF4444; }
  .admin-cal-dot.mine { background: var(--teal); }

  .btn-adm {
    font-family: 'Fredoka One', cursive;
    font-size: 14px;
    padding: 8px 18px;
    border-radius: var(--r-pill);
    border: 2px solid var(--black);
    cursor: pointer;
    transition: all .12s;
    letter-spacing: .2px;
    position: relative;
    box-shadow: 0 4px 0 rgba(0,0,0,0.3);
  }
  .btn-adm::after {
    content: '';
    position: absolute;
    inset: 3px;
    border-radius: var(--r-pill);
    background: linear-gradient(180deg, rgba(255,255,255,.35) 0%, transparent 60%);
    pointer-events: none;
  }
  .btn-adm:hover { filter: brightness(1.08); transform: translateY(-2px); box-shadow: 0 6px 0 rgba(0,0,0,0.3); }
  .btn-adm:active { transform: translateY(3px); box-shadow: 0 1px 0 rgba(0,0,0,0.3); filter: brightness(.95); }

  .btn-adm-y     { background: linear-gradient(180deg, #FFF176 0%, #FFE347 55%, #E6C800 100%); color: var(--black); border-color: #B8A000; }
  .btn-adm-g     { background: rgba(255,255,255,.08); color: rgba(255,255,255,.65); border-color: #444; box-shadow: 0 3px 0 #000; }
  .btn-adm-green { background: linear-gradient(180deg, #4ADE80 0%, #22C55E 55%, #15803D 100%); color: white; border-color: #15803D; }
  .btn-adm-red   { background: rgba(239,68,68,.18); color: #FCA5A5; border-color: rgba(239,68,68,.4); box-shadow: none; }

  .st-badge { font-size: 11px; font-weight: 800; padding: 3px 10px; border-radius: 20px; text-transform: capitalize; letter-spacing: .3px; }
  .st-draft { background: rgba(255,255,255,.08); color: rgba(255,255,255,.4); }
  .st-published { background: rgba(34,197,94,.18); color: #86EFAC; }
  .st-scheduled { background: rgba(255,227,71,.14); color: var(--yellow); }

  .q-row { background: #12121E; border: 1.5px solid rgba(45,212,191,.12); border-radius: 14px; padding: 9px 11px; margin-bottom: 6px; display: flex; gap: 9px; align-items: center; transition: border-color .12s, background .12s, opacity .12s; }
  .q-row.dragging { opacity: .45; border-color: var(--yellow); background: rgba(255,227,71,.08); }
  .q-row.drag-over { border-color: var(--teal); background: rgba(45,212,191,.1); }
  .q-drag { width: 20px; align-self: stretch; display: flex; align-items: center; justify-content: center; color: rgba(255,255,255,.25); font-size: 18px; cursor: grab; user-select: none; }
  .q-drag:active { cursor: grabbing; }
  .q-num { width: 26px; height: 26px; border-radius: 50%; background: linear-gradient(180deg,#5EEAD4,#2DD4BF 60%,#0F9488); border: 2px solid var(--teal-dark); display: flex; align-items: center; justify-content: center; font-family: 'Fredoka One', cursive; font-size: 12px; color: var(--black); flex-shrink: 0; box-shadow: 0 3px 0 var(--teal-dark); }
  .q-inf { flex: 1; }
  .q-txt { font-size: 14px; font-weight: 700; color: white; margin-bottom: 2px; }
  .q-meta { font-size: 11px; color: rgba(45,212,191,.5); font-weight: 600; }
  .q-correct { display: inline-block; background: rgba(45,212,191,.15); color: var(--teal); font-size: 11px; font-weight: 800; padding: 2px 8px; border-radius: 10px; margin-top: 3px; border: 1px solid rgba(45,212,191,.3); }
  .q-form-box { background: rgba(45,212,191,.05); border-radius: 14px; padding: 10px; margin: 6px 0 9px; border: 1.5px solid rgba(45,212,191,.15); }
  .q-form-title { font-family: 'Fredoka One', cursive; font-size: 14px; color: var(--teal); margin-bottom: 8px; }
  .q-form-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 8px; align-items: start; }
  .q-form-wide { grid-column: 1 / -1; }
  .q-form-box .adm-ta { min-height: 50px; }
  .q-actions { display: flex; gap: 5px; align-items: center; }
  .q-trash { min-width: 34px; }

  .count-bar { font-size: 13px; font-weight: 700; padding: 7px 11px; border-radius: 10px; margin-bottom: 10px; background: rgba(45,212,191,.06); border: 1px solid rgba(45,212,191,.1); }
  .count-bar.ok { color: var(--teal); }
  .count-bar.bad { color: #FCA5A5; }

  .tog-pair { display: flex; gap: 7px; margin-top: 5px; }
  .tog { flex: 1; padding: 8px; border-radius: 10px; border: 1.5px solid rgba(45,212,191,.2); background: transparent; color: rgba(255,255,255,.35); font-family: 'Nunito', sans-serif; font-size: 13px; font-weight: 800; cursor: pointer; transition: all .14s; text-align: center; }
  .tog.on { border-color: var(--teal); background: rgba(45,212,191,.12); color: var(--teal); }

  /* ===== LOGIN ===== */
  .login-pg { min-height: 100vh; background: var(--yellow); background-image: radial-gradient(circle,#1A1A1A 1.2px,transparent 1.2px); background-size: 24px 24px; display: flex; align-items: center; justify-content: center; padding: 24px; }
  .login-card { background: linear-gradient(160deg, #FFFEF5 0%, #FFF8E7 100%); border: 3px solid var(--black); border-radius: 28px; padding: 36px 28px; width: 100%; max-width: 340px; text-align: center; box-shadow: 0 10px 0 rgba(0,0,0,0.2), 0 12px 0 rgba(0,0,0,0.08); position: relative; overflow: hidden; }
  .login-card::before { content: ''; position: absolute; top: 6px; left: 14px; right: 14px; height: 18%; border-radius: 20px 20px 50% 50%; background: linear-gradient(180deg, rgba(255,255,255,.65) 0%, rgba(255,255,255,0) 100%); pointer-events: none; }
  .login-logo { font-family: 'Fredoka One', cursive; font-size: 26px; margin-bottom: 4px; line-height: 1.25; }
  .login-sub { font-size: 13px; font-weight: 700; color: var(--teal-dark); margin-bottom: 24px; letter-spacing: 1px; text-transform: uppercase; }
  .login-err { background: linear-gradient(160deg,#FEE2E2,#FECACA); border: 2px solid var(--red-dark); border-radius: 14px; color: var(--red-dark); font-size: 13px; font-weight: 800; padding: 9px; margin-bottom: 11px; }

  /* ===== TOAST ===== */
  .toast { position: fixed; bottom: 26px; left: 50%; transform: translateX(-50%); background: linear-gradient(180deg,#5EEAD4 0%,#2DD4BF 55%,#0F9488 100%); color: var(--black); font-family: 'Fredoka One', cursive; font-size: 16px; padding: 11px 26px; border-radius: var(--r-pill); border: 2.5px solid var(--teal-dark); box-shadow: 0 5px 0 var(--teal-dark); z-index: 200; animation: toastIn .3s cubic-bezier(.34,1.3,.64,1), toastOut .3s ease 1.7s forwards; white-space: nowrap; }

  /* ===== NO GAME ===== */
  .no-game { background: linear-gradient(160deg, #FFFEF5 0%, #FFF8E7 100%); border: 3px solid var(--black); border-radius: 24px; padding: 40px 22px; box-shadow: 0 8px 0 rgba(0,0,0,0.18); text-align: center; position: relative; overflow: hidden; }
  .no-game::before { content: ''; position: absolute; top: 6px; left: 14px; right: 14px; height: 18%; border-radius: 18px 18px 50% 50%; background: linear-gradient(180deg, rgba(255,255,255,.6) 0%, rgba(255,255,255,0) 100%); pointer-events: none; }

  /* ===== SOUND TOGGLE ===== */
  .sound-btn { background: none; border: none; cursor: pointer; font-size: 18px; opacity: .7; transition: opacity .15s, transform .1s; padding: 4px; }
  .sound-btn:hover { opacity: 1; transform: scale(1.2); }

  /* ===== PREVIEW BANNER ===== */
  .prev-banner { background: var(--pink); color: white; font-family: 'Fredoka One', cursive; font-size: 13px; text-align: center; padding: 6px; letter-spacing: 1px; text-transform: uppercase; }

  /* ===== GAME HEADER IMAGE ===== */
  .game-header-img {
    width: 100%;
    height: auto;
    max-height: clamp(280px, 62vw, 520px);
    object-fit: contain;
    border-radius: 14px 14px 0 0;
    border-bottom: var(--ink);
    display: block;
    background: rgba(11, 26, 44, 0.16);
  }
  .game-header-img-wrap {
    margin: -24px -20px 16px -20px;
    border-radius: 14px 14px 0 0;
    overflow: hidden;
    border-bottom: var(--ink);
    display: flex;
    align-items: center;
    justify-content: center;
    background: linear-gradient(180deg, rgba(11,26,44,.12), rgba(11,26,44,.04));
  }
  .archive-thumb {
    width: 48px;
    height: 36px;
    object-fit: contain;
    border-radius: 8px;
    border: 2px solid var(--black);
    box-shadow: 2px 2px 0 var(--black);
    flex-shrink: 0;
    background: rgba(11, 26, 44, 0.12);
  }
  .lightning-mark {
    display: inline-block;
    object-fit: contain;
    vertical-align: middle;
    filter: drop-shadow(0 2px 0 rgba(0,0,0,.16));
  }

  /* ===== IMAGE UPLOADER ===== */
  .img-uploader {
    background: rgba(255,255,255,.04);
    border: 1.5px dashed rgba(255,255,255,.2);
    border-radius: 12px;
    padding: 8px;
    margin-top: 4px;
  }
  .img-tab-row {
    display: flex;
    gap: 0;
    margin-bottom: 7px;
    border: 1.5px solid rgba(255,255,255,.15);
    border-radius: 8px;
    overflow: hidden;
  }
  .img-tab {
    flex: 1;
    padding: 5px 7px;
    background: transparent;
    border: none;
    color: rgba(255,255,255,.35);
    font-family: 'Nunito', sans-serif;
    font-size: 11px;
    font-weight: 800;
    cursor: pointer;
    text-align: center;
    text-transform: uppercase;
    letter-spacing: .5px;
    transition: all .15s;
  }
  .img-tab.on { background: rgba(255,227,71,.15); color: var(--yellow); }
  .img-drop-zone {
    border: 2px dashed rgba(255,255,255,.2);
    border-radius: 10px;
    padding: 10px;
    text-align: center;
    cursor: pointer;
    transition: all .15s;
    position: relative;
  }
  .img-drop-zone:hover { border-color: var(--yellow); background: rgba(255,227,71,.04); }
  .img-drop-zone input[type=file] {
    position: absolute;
    inset: 0;
    opacity: 0;
    cursor: pointer;
    width: 100%;
    height: 100%;
  }
  .img-drop-lbl { font-size: 11px; font-weight: 700; color: rgba(255,255,255,.35); margin-top: 3px; }
  .img-preview {
    margin-top: 7px;
    border-radius: 10px;
    overflow: hidden;
    border: 1.5px solid rgba(255,255,255,.15);
    position: relative;
    background: rgba(0,0,0,.18);
  }
  .img-preview img { width: 100%; height: auto; max-height: 150px; object-fit: contain; display: block; background: rgba(0,0,0,.16); }
  .img-uploader-wrap.compact .img-preview img { max-height: 115px; }
  .img-uploader-wrap.preset-header .img-preview img { max-height: 180px; }
  .img-uploader-wrap.compact.preset-header .img-preview img { max-height: 150px; }
  .img-preview iframe { width: 100%; aspect-ratio: 16/9; min-height: 160px; display: block; border: 0; background: #000; }
  .img-preview-label {
    position: absolute;
    top: 6px; left: 6px;
    background: rgba(0,0,0,.6);
    color: var(--yellow);
    font-size: 10px;
    font-weight: 800;
    padding: 2px 8px;
    border-radius: 20px;
    letter-spacing: .5px;
    text-transform: uppercase;
  }
  .img-clear-btn {
    position: absolute;
    top: 6px; right: 6px;
    background: rgba(239,68,68,.8);
    color: white;
    border: none;
    border-radius: 50%;
    width: 22px; height: 22px;
    font-size: 13px;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    line-height: 1;
  }

  /* ===== ANIMATIONS ===== */
  @keyframes spinSlow { to { transform: rotate(360deg); } }
  @keyframes wobble {
    0%,100% { transform: rotate(-3deg) scale(1); }
    25%      { transform: rotate(4deg) scale(1.08); }
    75%      { transform: rotate(-4deg) scale(1.05); }
  }
  @keyframes spinWiggle {
    0%   { transform: rotate(0deg) scale(1); }
    25%  { transform: rotate(-18deg) scale(1.12); }
    75%  { transform: rotate(18deg) scale(1.12); }
    100% { transform: rotate(0deg) scale(1); }
  }
  @keyframes dotPulse {
    0%,100% { transform: scale(1.3); }
    50%      { transform: scale(1.5); }
  }
  @keyframes pulseFade {
    0%,100% { opacity: .5; }
    50%      { opacity: 1; }
  }
  @keyframes correctPop {
    0%  { transform: scale(1); }
    40% { transform: scale(1.06); }
    100%{ transform: scale(1); }
  }
  @keyframes wrongShake {
    0%,100%{ transform: translateX(0); }
    20%    { transform: translateX(-8px) rotate(-1deg); }
    40%    { transform: translateX(8px) rotate(1deg); }
    60%    { transform: translateX(-5px); }
    80%    { transform: translateX(5px); }
  }
  @keyframes reactionBoom {
    0%  { transform: scale(0) rotate(-20deg); opacity: 1; }
    60% { transform: scale(1.3) rotate(8deg); opacity: 1; }
    100%{ transform: scale(1.1) rotate(-3deg) translateY(-20px); opacity: 0; }
  }
  @keyframes cardSlideUp {
    from { transform: translateY(22px) scale(.97); opacity: 0; }
    to   { transform: translateY(0) scale(1);   opacity: 1; }
  }
  @keyframes comboAppear {
    0%  { transform: scale(0); opacity: 0; }
    70% { transform: scale(1.2); }
    100%{ transform: scale(1); opacity: 1; }
  }
  @keyframes popIn {
    0%  { transform: scale(0) rotate(-20deg); opacity: 0; }
    70% { transform: scale(1.3) rotate(5deg); }
    100%{ transform: scale(1) rotate(0); opacity: 1; }
  }
  @keyframes shinePulse {
    0%,100% { filter: brightness(1); }
    50%     { filter: brightness(1.08); }
  }
  @keyframes toastIn { from { transform: translateX(-50%) translateY(18px) scale(.9); opacity: 0; } to { transform: translateX(-50%) translateY(0) scale(1); opacity: 1; } }
  @keyframes toastOut { to { opacity: 0; transform: translateX(-50%) translateY(10px); } }
  @keyframes slideUp { from { transform: translateY(18px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
  .slide-up { animation: slideUp .3s ease; }
`;

const LIGHTNING_ICON_SRC = "/lightning-finished.png";
function LightningMark({size=22, alt="Lightning", style={}}){
  return <img src={LIGHTNING_ICON_SRC} alt={alt} className="lightning-mark" style={{width:size,height:size,...style}} />;
}

// ============================================================
// SOUND ENGINE — Web Audio API, no external deps
// ============================================================
function useSoundEngine() {
  const [muted, setMuted] = useState(false);
  const ctx = useRef(null);

  const getCtx = () => {
    if (!ctx.current) ctx.current = new (window.AudioContext || window.webkitAudioContext)();
    if (ctx.current.state === 'suspended') ctx.current.resume();
    return ctx.current;
  };

  // Helper: play a single note with its own gain node — no shared state
  const note = (c, type, freq, startT, peakVol, peakT, fadeEndT) => {
    const o = c.createOscillator();
    const g = c.createGain();
    o.connect(g);
    g.connect(c.destination);
    o.type = type;
    o.frequency.value = freq;
    g.gain.setValueAtTime(0.0001, startT);
    g.gain.linearRampToValueAtTime(peakVol, startT + peakT);
    g.gain.linearRampToValueAtTime(0.0001, fadeEndT);  // linear fade, not exponential — no click
    o.start(startT);
    o.stop(fadeEndT + 0.02);  // stop slightly after fade — clean cutoff
  };

  const play = useCallback((type) => {
    if (muted) return;
    try {
      const c = getCtx();
      const t = c.currentTime;

      if (type === 'correct') {
        note(c, 'sine', 523, t,        0.15, 0.02, t + 0.22);
        note(c, 'sine', 659, t + 0.1,  0.15, 0.02, t + 0.32);
        note(c, 'sine', 784, t + 0.2,  0.15, 0.02, t + 0.42);
      } else if (type === 'wrong') {
        const o = c.createOscillator();
        const g = c.createGain();
        o.connect(g); g.connect(c.destination);
        o.type = 'sawtooth';
        o.frequency.setValueAtTime(280, t);
        o.frequency.linearRampToValueAtTime(90, t + 0.28);
        g.gain.setValueAtTime(0.12, t);
        g.gain.linearRampToValueAtTime(0.0001, t + 0.3);
        o.start(t); o.stop(t + 0.32);
      } else if (type === 'combo') {
        note(c, 'triangle', 880,  t,        0.1, 0.015, t + 0.18);
        note(c, 'triangle', 1100, t + 0.07, 0.1, 0.015, t + 0.25);
        note(c, 'triangle', 1320, t + 0.14, 0.1, 0.015, t + 0.32);
      } else if (type === 'perfect') {
        note(c, 'sine', 523,  t,        0.1, 0.02, t + 0.3);
        note(c, 'sine', 659,  t + 0.1,  0.1, 0.02, t + 0.4);
        note(c, 'sine', 784,  t + 0.2,  0.1, 0.02, t + 0.5);
        note(c, 'sine', 1047, t + 0.32, 0.1, 0.02, t + 0.65);
      } else if (type === 'click') {
        note(c, 'sine', 480, t, 0.07, 0.005, t + 0.07);
      }
    } catch (e) { /* audio unavailable */ }
  }, [muted]);

  return { play, muted, setMuted };
}

// ============================================================
// CONFETTI CANNON — canvas-based, physics
// ============================================================
function useConfetti() {
  const canvasRef = useRef(null);
  const particles = useRef([]);
  const rafId = useRef(null);

  const shoot = useCallback((intensity = 'normal') => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const colors = ['#FFE347','#FF5C8D','#2DD4BF','#22C55E','#FF8C00','#A855F7','#FFFEF5','#60A5FA'];
    const count = intensity === 'perfect' ? 120 : 55;

    for (let i = 0; i < count; i++) {
      particles.current.push({
        x: Math.random() * canvas.width,
        y: -10,
        vx: (Math.random() - 0.5) * 8,
        vy: Math.random() * 4 + 2,
        rot: Math.random() * 360,
        rotV: (Math.random() - 0.5) * 8,
        size: Math.random() * 10 + 6,
        color: colors[Math.floor(Math.random() * colors.length)],
        shape: Math.random() > 0.5 ? 'rect' : 'circle',
        gravity: 0.18 + Math.random() * 0.1,
        life: 1,
        decay: Math.random() * 0.008 + 0.006,
      });
    }

    const draw = () => {
      const ctx = canvas.getContext('2d');
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      particles.current = particles.current.filter(p => p.life > 0);

      for (const p of particles.current) {
        ctx.save();
        ctx.globalAlpha = p.life;
        ctx.translate(p.x, p.y);
        ctx.rotate(p.rot * Math.PI / 180);
        ctx.fillStyle = p.color;
        ctx.strokeStyle = '#1A1A1A';
        ctx.lineWidth = 1.5;
        if (p.shape === 'rect') {
          ctx.fillRect(-p.size / 2, -p.size / 4, p.size, p.size / 2);
          ctx.strokeRect(-p.size / 2, -p.size / 4, p.size, p.size / 2);
        } else {
          ctx.beginPath();
          ctx.arc(0, 0, p.size / 2, 0, Math.PI * 2);
          ctx.fill();
          ctx.stroke();
        }
        ctx.restore();

        p.x += p.vx;
        p.y += p.vy;
        p.vy += p.gravity;
        p.vx *= 0.99;
        p.rot += p.rotV;
        p.life -= p.decay;
      }

      if (particles.current.length > 0) rafId.current = requestAnimationFrame(draw);
      else ctx.clearRect(0, 0, canvas.width, canvas.height);
    };

    if (rafId.current) cancelAnimationFrame(rafId.current);
    draw();
  }, []);

  return { canvasRef, shoot };
}

// ============================================================
// SUPABASE CLIENT
// ============================================================
const SB_URL = import.meta.env.VITE_SUPABASE_URL?.trim() || "";
const SB_KEY = import.meta.env.VITE_SUPABASE_ANON_KEY?.trim() || "";
const SUPABASE_READY = Boolean(SB_URL && SB_KEY);
const supabase = SUPABASE_READY ? createClient(SB_URL, SB_KEY, {
  auth: {
    persistSession: true,
    autoRefreshToken: true,
    detectSessionInUrl: true
  }
}) : null;
const AUTH_TIMEOUT_MS = 8000;
const APP_BOOT_TIMEOUT_MS = 14000;

function withTimeout(promise, ms, message){
  let timer;
  return Promise.race([
    Promise.resolve(promise).finally(()=>clearTimeout(timer)),
    new Promise((_,reject)=>{
      timer = setTimeout(()=>reject(new Error(message)), ms);
    })
  ]);
}

function clearSupabaseAuthCache(){
  if(typeof localStorage==="undefined") return;
  const keys = [];
  for(let i=0;i<localStorage.length;i++){
    const key = localStorage.key(i);
    if(key&&key.startsWith("sb-")&&key.includes("auth-token")) keys.push(key);
  }
  keys.forEach(key=>safeRemove(key));
}

function isAnonymousUser(user){
  return Boolean(user?.is_anonymous ?? (!user?.email && (!Array.isArray(user?.identities) || user.identities.length===0)));
}
async function getAuthSession(){
  if(!supabase) return null;
  const { data, error } = await withTimeout(
    supabase.auth.getSession(),
    AUTH_TIMEOUT_MS,
    "Auth session check timed out."
  );
  if(error) throw error;
  return data.session;
}
async function authEnsureSession({recover=false}={}){
  if(!supabase) throw new Error("Supabase Auth is not configured.");
  let existing = null;
  try{
    existing = await getAuthSession();
  }catch(e){
    if(!recover) throw e;
    clearSupabaseAuthCache();
  }
  if(existing?.user) return existing;
  const { data, error } = await withTimeout(
    supabase.auth.signInAnonymously(),
    AUTH_TIMEOUT_MS,
    "Guest sign-in timed out."
  );
  if(error) throw error;
  return data.session;
}
async function authSendMagicLink(email){
  if(!supabase) throw new Error("Supabase Auth is not configured.");
  const { error } = await supabase.auth.signInWithOtp({
    email,
    options: { emailRedirectTo: window.location.origin }
  });
  if(error) throw error;
}
async function authCreatePasswordAccount(email, password){
  if(!supabase) throw new Error("Supabase Auth is not configured.");
  const existing = await getAuthSession();
  if(isAnonymousUser(existing?.user)){
    const { error: signOutError } = await supabase.auth.signOut();
    if(signOutError) throw signOutError;
  }
  const { data, error } = await supabase.auth.signUp({
    email,
    password
  });
  if(error) throw error;
  return data.user;
}
async function authSignInWithPassword(email, password){
  if(!supabase) throw new Error("Supabase Auth is not configured.");
  const existing = await getAuthSession();
  if(isAnonymousUser(existing?.user)){
    const { error: signOutError } = await supabase.auth.signOut();
    if(signOutError) throw signOutError;
  }
  const { data, error } = await supabase.auth.signInWithPassword({
    email,
    password
  });
  if(error) throw error;
  return data.user;
}
async function authSignOutToGuest(){
  if(!supabase) return null;
  const { error } = await supabase.auth.signOut();
  if(error) throw error;
  return authEnsureSession();
}
function authSubscribe(onChange){
  if(!supabase) return { data: { subscription: { unsubscribe(){} } } };
  return supabase.auth.onAuthStateChange((event, session)=>onChange(event, session));
}
function formatAuthError(err){
  const msg = err?.message||"Something went sideways.";
  if(msg.toLowerCase().includes("anonymous sign-ins")) return "Enable Anonymous Sign-Ins in Supabase Auth first.";
  if(msg.toLowerCase().includes("email rate limit")) return "Too many email requests. Try again in a minute.";
  if(msg.toLowerCase().includes("invalid login credentials")) return "That email and password do not match an account.";
  if(msg.toLowerCase().includes("user already registered")) return "That email already has an account. Try signing in instead.";
  if(msg.toLowerCase().includes("password should be at least")) return "Passwords need at least 6 characters.";
  if(msg.toLowerCase().includes("email not confirmed")) return "That account still needs to be confirmed before it can sign in.";
  return msg;
}

async function sbFetch(path, opts={}){
  if(!SUPABASE_READY) throw new Error("Supabase is not configured.");
  let session = await getAuthSession();
  if(!session?.access_token && supabase){
    try{
      session = await authEnsureSession();
    }catch{
      session = null;
    }
  }
  const accessToken = session?.access_token || SB_KEY;
  const res = await fetch(`${SB_URL}${path}`, {
    ...opts,
    headers:{
      "apikey": SB_KEY,
      "Authorization": `Bearer ${accessToken}`,
      "Content-Type": "application/json",
      "Prefer": "return=representation",
      ...(opts.headers||{})
    }
  });
  if(!res.ok){
    const err = await res.text();
    throw new Error(`Supabase error ${res.status}: ${err}`);
  }
  const text = await res.text();
  return text ? JSON.parse(text) : null;
}

// ===== IMAGE UPLOAD to Supabase Storage =====
const STORAGE_BUCKET = "wtf-images";
const STORAGE_PUBLIC_PREFIX = `${SB_URL}/storage/v1/object/public/${STORAGE_BUCKET}/`;
const IMPORT_IMAGE_TIMEOUT_MS = 14000;

function isStorageImageUrl(value){
  if(!value || !SUPABASE_READY) return false;
  return String(value).startsWith(STORAGE_PUBLIC_PREFIX);
}
function isImportableExternalImageUrl(value){
  if(!value || String(value).startsWith("data:") || isYouTubeUrl(value) || isStorageImageUrl(value)) return false;
  try{
    const url = new URL(value);
    return url.protocol==="http:" || url.protocol==="https:";
  }catch{
    return false;
  }
}
async function uploadBytesToStorage(bytes, mime, folder="images"){
  if(!SUPABASE_READY) throw new Error("Supabase is not configured.");
  const cleanMime = mime || "image/png";
  const ext = (cleanMime.split("/")[1] || "png").replace(/[^a-z0-9]/gi,"").replace(/^jpeg$/,"jpg") || "png";
  const filename = `${folder}/${Date.now()}-${Math.random().toString(36).slice(2)}.${ext}`;
  let session = null;
  try{ session = await getAuthSession(); }catch{}
  const postWithToken = token=>fetch(`${SB_URL}/storage/v1/object/${STORAGE_BUCKET}/${filename}`, {
    method:"POST",
    headers:{
      "apikey": SB_KEY,
      "Authorization": `Bearer ${token}`,
      "Content-Type": cleanMime,
      "Cache-Control": "31536000"
    },
    body: bytes
  });
  let res = await postWithToken(session?.access_token || SB_KEY);
  if(!res.ok && session?.access_token) res = await postWithToken(SB_KEY);
  if(!res.ok) throw new Error(`Image upload failed: ${await res.text()}`);
  return `${STORAGE_PUBLIC_PREFIX}${filename}`;
}
async function uploadImage(dataUri, folder="images"){
  if(!dataUri || !dataUri.startsWith("data:")) return dataUri; // already a URL
  const [meta, b64] = dataUri.split(",");
  const mime = meta.match(/:(.*?);/)[1];
  const bytes = Uint8Array.from(atob(b64), c=>c.charCodeAt(0));
  return uploadBytesToStorage(bytes, mime, folder);
}
async function importExternalImageUrl(value, {folder="images", preset="default", label="image"}={}){
  if(!isImportableExternalImageUrl(value)) return value;
  let response;
  try{
    response = await withTimeout(
      fetch(value, {mode:"cors", redirect:"follow"}),
      IMPORT_IMAGE_TIMEOUT_MS,
      `Import timed out for ${label}.`
    );
  }catch{
    throw new Error(`Couldn't import ${label}. Try uploading the image file instead.`);
  }
  if(!response.ok) throw new Error(`Couldn't import ${label}. The image URL returned ${response.status}.`);
  const type = response.headers.get("content-type") || "";
  const blob = await response.blob();
  const mime = blob.type || type;
  if(!mime.startsWith("image/")) throw new Error(`Couldn't import ${label}. That URL did not return an image.`);
  const dataUrl = await fileToDataUrl(blob);
  const optimized = await optimizeImageDataUrl(dataUrl, preset);
  return uploadImage(optimized, folder);
}
async function prepareImageForSave(value, options, archiveExternal=false){
  if(!value) return value;
  if(String(value).startsWith("data:")) return uploadImage(value, options?.folder);
  if(archiveExternal) return importExternalImageUrl(value, options);
  return value;
}

// ===== GAME → DB row conversion =====
function gameToRow(g){
  return {
    id: g.id,
    date: g.date,
    theme_title: g.themeTitle,
    category_a: g.categoryA,
    category_b: g.categoryB,
    category_a_color: g.categoryAColor||null,
    category_b_color: g.categoryBColor||null,
    category_a_image: g.categoryAImage||null,
    category_b_image: g.categoryBImage||null,
    header_image: g.headerImage||null,
    status: g.status,
    questions: g.questions||[]
  };
}
function rowToGame(r){
  return {
    id: r.id,
    date: r.date,
    themeTitle: r.theme_title,
    categoryA: r.category_a,
    categoryB: r.category_b,
    categoryAColor: r.category_a_color,
    categoryBColor: r.category_b_color,
    categoryAImage: r.category_a_image,
    categoryBImage: r.category_b_image,
    headerImage: r.header_image,
    status: r.status,
    questions: r.questions||[]
  };
}

// ===== DB FUNCTIONS — GAMES =====
async function dbLoadGames(){
  const rows = await sbFetch("/rest/v1/games?select=*&order=date.desc");
  return (rows||[]).map(rowToGame);
}
async function dbLoadPublishedGames(){
  const rows = await sbFetch("/rest/v1/games?select=*&status=eq.published&order=date.desc");
  return (rows||[]).map(rowToGame);
}
async function dbSaveGame(game){
  // Upload pasted files immediately; archive external image URLs only once the puzzle is published.
  const archiveExternal = game.status==="published";
  const toUpload = [
    ["categoryAImage", {folder:"categories", preset:"category", label:"Category A image"}],
    ["categoryBImage", {folder:"categories", preset:"category", label:"Category B image"}],
    ["headerImage", {folder:"headers", preset:"header", label:"header image"}]
  ];
  const uploaded = {...game};
  for(const [field, options] of toUpload){
    uploaded[field] = await prepareImageForSave(uploaded[field], options, archiveExternal);
  }
  // Also upload question images
  if(uploaded.questions){
    uploaded.questions = await Promise.all(uploaded.questions.map(async q=>{
      const original = q.imageUrl;
      const imageUrl = await prepareImageForSave(original, {folder:"questions", preset:"question", label:`question image${q.itemText?` for "${q.itemText}"`:""}`}, archiveExternal);
      if(imageUrl!==original && isImportableExternalImageUrl(original)) return {...q, imageUrl, originalImageUrl:q.originalImageUrl||original};
      if(imageUrl!==original) return {...q, imageUrl};
      return q;
    }));
  }
  const row = gameToRow(uploaded);
  await sbFetch("/rest/v1/games", {
    method:"POST",
    headers:{"Prefer":"resolution=merge-duplicates"},
    body: JSON.stringify(row)
  });
  return uploaded;
}
async function dbDeleteGame(id){
  await sbFetch(`/rest/v1/games?id=eq.${encodeURIComponent(id)}`, {method:"DELETE"});
}

// ===== DB FUNCTIONS — PLAYERS =====
async function dbGetOrCreatePlayer(user){
  if(!user) return null;
  try{
    await sbFetch("/rest/v1/players", {
      method:"POST",
      headers:{"Prefer":"resolution=ignore-duplicates"},
      body: JSON.stringify({
        id: user.id,
        email: user.email||null,
        is_guest: isAnonymousUser(user),
        last_seen_at: new Date().toISOString()
      })
    });
  }catch(e){
    if(!String(e?.message||"").includes("duplicate key")) throw e;
  }
  const rows = await sbFetch(`/rest/v1/players?id=eq.${user.id}&select=*`);
  const row = rows?.[0];
  return {
    id: user.id,
    email: row?.email ?? user.email ?? null,
    isGuest: row?.is_guest ?? isAnonymousUser(user),
    createdAt: row?.created_at ?? user.created_at ?? new Date().toISOString()
  };
}

// ===== DB FUNCTIONS — GAME RECORDS =====
async function dbGetGameRecord(playerId, date){
  try {
    const rows = await sbFetch(`/rest/v1/game_records?player_id=eq.${playerId}&game_date=eq.${date}&select=*`);
    if(!rows||!rows.length) return null;
    const r = rows[0];
    return {
      date: r.game_date,
      themeTitle: r.theme_title,
      score: r.score,
      totalQuestions: r.total_questions,
      currentIndex: r.answers?.length||0,
      answers: r.answers||[],
      completed: r.completed,
      startedAt: r.started_at,
      completedAt: r.completed_at
    };
  } catch(e){ return null; }
}
async function dbInitGameRecord(playerId, date, themeTitle, total){
  const existing = await dbGetGameRecord(playerId, date);
  if(existing) return existing;
  await sbFetch("/rest/v1/game_records", {
    method:"POST",
    headers:{"Prefer":"resolution=ignore-duplicates"},
    body: JSON.stringify({
      player_id: playerId, game_date: date, theme_title: themeTitle,
      score:0, total_questions:total, answers:[], completed:false
    })
  });
  return {date,themeTitle,score:0,totalQuestions:total,currentIndex:0,answers:[],completed:false,startedAt:new Date().toISOString(),completedAt:null};
}
async function dbRecordAnswer(playerId, date, answers, score){
  await sbFetch(`/rest/v1/game_records?player_id=eq.${playerId}&game_date=eq.${date}`, {
    method:"PATCH",
    body: JSON.stringify({answers, score})
  });
}
async function dbCompleteGame(playerId, date, answers, score, totalQuestions){
  await sbFetch(`/rest/v1/game_records?player_id=eq.${playerId}&game_date=eq.${date}`, {
    method:"PATCH",
    body: JSON.stringify({answers, score, completed:true, completed_at:new Date().toISOString()})
  });
  // Update stats
  await dbUpdateStats(playerId, date, score, totalQuestions, answers);
}
async function dbGetPuzzleCommunityStats(date, userScore){
  try {
    const rows = await sbFetch(`/rest/v1/puzzle_stats?game_date=eq.${date}&select=*`);
    const stats = rows?.[0];
    if(!stats){
      return {
        finishedPlayers: 0,
        averageScore: 0,
        beatRate: 0,
        perfectRate: 0,
        questionAccuracies: []
      };
    }
    const totalQuestions = stats.total_questions||0;
    const histogram = stats.score_histogram||{};
    const beatenCount = Object.entries(histogram).reduce((sum,[score,count])=>{
      return Number(score)<=userScore ? sum + (Number(count)||0) : sum;
    },0);
    const correctCounts = Array.isArray(stats.question_correct_counts) ? stats.question_correct_counts : [];
    const answerCounts = Array.isArray(stats.question_answer_counts) ? stats.question_answer_counts : [];
    const questionAccuracies = Array.from({length:totalQuestions},(_,idx)=>{
      const answered = Number(answerCounts[idx]||0);
      const correct = Number(correctCounts[idx]||0);
      return {
        index: idx,
        correctRate: answered ? Math.round(correct/answered*100) : 0
      };
    });
    return {
      finishedPlayers: stats.total_finished||0,
      averageScore: stats.total_finished ? Math.round((stats.total_score||0)/stats.total_finished) : 0,
      beatRate: stats.total_finished ? Math.round(beatenCount/stats.total_finished*100) : 0,
      perfectRate: stats.total_finished ? Math.round((stats.perfect_count||0)/stats.total_finished*100) : 0,
      questionAccuracies
    };
  } catch(e){
    return null;
  }
}

// ===== DB FUNCTIONS — STATS =====
async function dbGetStats(playerId){
  try {
    const rows = await sbFetch(`/rest/v1/player_stats?player_id=eq.${playerId}&select=*`);
    if(!rows||!rows.length) return {currentStreak:0,longestStreak:0,lastPlayedDate:null,totalPlayed:0,totalCorrect:0,totalQuestions:0,bestCombo:0};
    const r = rows[0];
    return {currentStreak:r.current_streak,longestStreak:r.longest_streak,lastPlayedDate:r.last_played_date,totalPlayed:r.total_played,totalCorrect:r.total_correct,totalQuestions:r.total_questions,bestCombo:r.best_combo};
  } catch(e){ return {currentStreak:0,longestStreak:0,lastPlayedDate:null,totalPlayed:0,totalCorrect:0,totalQuestions:0,bestCombo:0}; }
}
async function dbUpdateStats(playerId, date, score, totalQuestions, answers){
  const s = await dbGetStats(playerId);
  const yd = new Date(); yd.setDate(yd.getDate()-1);
  const yds = yd.toLocaleDateString("en-CA");
  if(s.lastPlayedDate===yds) s.currentStreak+=1;
  else if(s.lastPlayedDate!==date) s.currentStreak=1;
  s.longestStreak = Math.max(s.longestStreak, s.currentStreak);
  s.lastPlayedDate = date;
  s.totalPlayed+=1;
  s.totalCorrect+=score;
  s.totalQuestions+=totalQuestions;
  const best = calcBestCombo(answers);
  if(best>s.bestCombo) s.bestCombo=best;
  await sbFetch("/rest/v1/player_stats", {
    method:"POST",
    headers:{"Prefer":"resolution=merge-duplicates"},
    body: JSON.stringify({
      player_id:playerId,
      current_streak:s.currentStreak, longest_streak:s.longestStreak,
      last_played_date:s.lastPlayedDate, total_played:s.totalPlayed,
      total_correct:s.totalCorrect, total_questions:s.totalQuestions,
      best_combo:s.bestCombo, updated_at:new Date().toISOString()
    })
  });
  return s;
}

// ============================================================
// DATA LAYER — local helpers kept for non-async usage
// ============================================================
const ADMIN_PASS = "admin123";
function safeRead(k){try{const v=localStorage.getItem(k);return v?JSON.parse(v):null;}catch{return null;}}
function safeWrite(k,v){try{localStorage.setItem(k,JSON.stringify(v));return true;}catch{return false;}}
function safeRemove(k){try{localStorage.removeItem(k);return true;}catch{return false;}}
function calcBestCombo(answers){let best=0,cur=0;for(const a of answers){if(a.correct){cur++;best=Math.max(best,cur);}else cur=0;}return best;}
function getLocalGameDay(){return new Date().toLocaleDateString("en-CA");}
function isoFromLocalDate(date){
  if(!(date instanceof Date)||Number.isNaN(date.getTime())) return "";
  const y = date.getFullYear();
  const m = String(date.getMonth()+1).padStart(2,"0");
  const d = String(date.getDate()).padStart(2,"0");
  return `${y}-${m}-${d}`;
}
function localDateFromISO(iso){
  const match = String(iso||"").match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if(!match) return null;
  const y = Number(match[1]);
  const m = Number(match[2]);
  const d = Number(match[3]);
  const date = new Date(y, m-1, d);
  if(date.getFullYear()!==y||date.getMonth()!==m-1||date.getDate()!==d) return null;
  return date;
}
function formatAdminDate(iso){
  const date = localDateFromISO(iso);
  if(!date) return iso||"";
  return `${String(date.getMonth()+1).padStart(2,"0")}/${String(date.getDate()).padStart(2,"0")}/${date.getFullYear()}`;
}
function parseAdminDate(value){
  const raw = String(value||"").trim();
  const us = raw.match(/^(\d{1,2})[/-](\d{1,2})[/-](\d{4})$/);
  if(us){
    const m = Number(us[1]);
    const d = Number(us[2]);
    const y = Number(us[3]);
    const date = new Date(y, m-1, d);
    if(date.getFullYear()===y&&date.getMonth()===m-1&&date.getDate()===d) return isoFromLocalDate(date);
  }
  const iso = localDateFromISO(raw);
  return iso ? raw : "";
}
function getCountdown(){const n=new Date();const t=new Date(n);t.setDate(t.getDate()+1);t.setHours(0,0,0,0);const d=t-n;return`${String(Math.floor(d/3600000)).padStart(2,"0")}:${String(Math.floor((d%3600000)/60000)).padStart(2,"0")}:${String(Math.floor((d%60000)/1000)).padStart(2,"0")}`;}
function parseYouTubeStart(value){
  const raw = String(value||"").trim();
  if(!raw) return 0;
  if(/^\d+$/.test(raw)) return Number(raw);
  let total = 0;
  let matched = false;
  raw.replace(/(\d+)(h|m|s)/gi,(_,amount,unit)=>{
    matched = true;
    const n = Number(amount)||0;
    if(unit.toLowerCase()==="h") total += n*3600;
    if(unit.toLowerCase()==="m") total += n*60;
    if(unit.toLowerCase()==="s") total += n;
    return "";
  });
  return matched ? total : 0;
}
function getYouTubeEmbedUrl(value){
  if(!value) return null;
  try{
    const url = new URL(value);
    const host = url.hostname.replace(/^www\./,"").toLowerCase();
    let id = "";
    if(host==="youtu.be"){
      id = url.pathname.split("/").filter(Boolean)[0]||"";
    }else if(host==="youtube.com"||host==="m.youtube.com"||host==="music.youtube.com"||host==="youtube-nocookie.com"){
      const parts = url.pathname.split("/").filter(Boolean);
      if(url.pathname==="/watch") id = url.searchParams.get("v")||"";
      else if(["embed","shorts","live"].includes(parts[0])) id = parts[1]||"";
    }
    if(!/^[a-zA-Z0-9_-]{11}$/.test(id)) return null;
    const start = parseYouTubeStart(url.searchParams.get("start")||url.searchParams.get("t")||"");
    return `https://www.youtube-nocookie.com/embed/${id}${start?`?start=${start}`:""}`;
  }catch{
    return null;
  }
}
function isYouTubeUrl(value){return Boolean(getYouTubeEmbedUrl(value));}
function formatAccountLabel(email){
  if(!email) return "Account";
  if(email.length<=18) return email;
  const parts = email.split("@");
  if(parts.length!==2) return `${email.slice(0,15)}...`;
  return `${parts[0].slice(0,10)}...@${parts[1]}`;
}
function getEditorDraftKey(id){return `wtf-editor-draft:${id||"unsaved"}`;}
function normalizeEditorDraft(game){
  return {
    ...game,
    status: game.status==="published" ? "published" : "draft",
    questions: game.questions||[]
  };
}
function loadEditorDraft(game){
  if(!game?.id) return game;
  const saved = safeRead(getEditorDraftKey(game.id));
  return saved?.game ? {...game, ...saved.game, id: game.id} : game;
}
function saveEditorDraft(game){
  if(!game?.id) return false;
  return safeWrite(getEditorDraftKey(game.id), {
    savedAt: Date.now(),
    game: normalizeEditorDraft(game)
  });
}
function clearEditorDraft(id){
  if(!id) return false;
  return safeRemove(getEditorDraftKey(id));
}
function scoreMsg(s,t){const p=s/t;if(p===1)return"🏆 PERFECT!! Absolutely flawless. You are the champion.";if(p>=.875)return"Almost perfect!! Just one little slip.";if(p>=.75)return"Really solid! The theme tried hard. It mostly failed.";if(p>=.5)return"Decent showing! Some of those were genuinely sneaky.";if(p>=.25)return"The theme had you. It happens to everyone.";return"Wow okay. The theme absolutely won today. Tomorrow!";}
function buildShare(gr){
  const answers = Array.isArray(gr?.answers) ? gr.answers : [];
  const g=answers.map(a=>a.correct?"🟢":"🔴").join("");
  return`What The Fudge Trivia 🍬\n${gr?.themeTitle||"Puzzle Results"}\n${gr?.score||0}/${gr?.totalQuestions||0} ${g}\nwhatthefudgetrivia.com`;
}
const IMAGE_UPLOAD_PRESETS = {
  default: { maxWidth: 1600, maxHeight: 1600, quality: 0.82 },
  header: { maxWidth: 1600, maxHeight: 900, quality: 0.82 },
  category: { maxWidth: 1200, maxHeight: 1200, quality: 0.82 },
  question: { maxWidth: 1400, maxHeight: 1400, quality: 0.84 }
};
function fileToDataUrl(file){
  return new Promise((resolve,reject)=>{
    const reader = new FileReader();
    reader.onload = ev=>resolve(ev.target?.result||"");
    reader.onerror = ()=>reject(new Error("Couldn't read image file."));
    reader.readAsDataURL(file);
  });
}
function loadImageElement(src){
  return new Promise((resolve,reject)=>{
    const img = new Image();
    img.onload = ()=>resolve(img);
    img.onerror = ()=>reject(new Error("Couldn't load image for optimization."));
    img.src = src;
  });
}
async function optimizeImageDataUrl(dataUrl,preset="default"){
  if(!dataUrl||!dataUrl.startsWith("data:image/")) return dataUrl;
  const presetCfg = IMAGE_UPLOAD_PRESETS[preset]||IMAGE_UPLOAD_PRESETS.default;
  const mimeMatch = dataUrl.match(/^data:(image\/[^;]+);/i);
  const inputMime = mimeMatch?.[1]?.toLowerCase()||"image/jpeg";
  if(inputMime==="image/svg+xml"||inputMime==="image/gif") return dataUrl;

  const img = await loadImageElement(dataUrl);
  const scale = Math.min(1, presetCfg.maxWidth/img.width, presetCfg.maxHeight/img.height);
  const targetWidth = Math.max(1, Math.round(img.width*scale));
  const targetHeight = Math.max(1, Math.round(img.height*scale));

  const canvas = document.createElement("canvas");
  canvas.width = targetWidth;
  canvas.height = targetHeight;
  const ctx = canvas.getContext("2d");
  if(!ctx) return dataUrl;
  ctx.drawImage(img, 0, 0, targetWidth, targetHeight);

  const outputMime = "image/webp";
  const optimized = canvas.toDataURL(outputMime, presetCfg.quality);
  return optimized.length < dataUrl.length ? optimized : dataUrl;
}
async function readOptimizedImageFile(file,preset="default"){
  const dataUrl = await fileToDataUrl(file);
  return optimizeImageDataUrl(dataUrl,preset);
}
function averageScoreCopy(score,total){
  return `Average chaos level: ${score}/${total}`;
}
function beatRateCopy(rate){
  if(rate>=90) return `You crushed ${rate}% of the crowd`;
  if(rate>=60) return `You out-weirded ${rate}% of players`;
  if(rate>=35) return `You edged out ${rate}% of players`;
  return `You survived better than ${rate}% of players`;
}
function perfectRateCopy(rate){
  if(rate===0) return "Nobody else nailed a perfect score yet";
  return `${rate}% joined the perfect goblin club`;
}


