function shouldKeepFitTextOnOneLine(value){
  const text = String(value||"").trim();
  return Boolean(text) && !/[\s-]/.test(text);
}

function FitText({children, className="", style, min=12, max=48, oneLine, as="div"}){
  const text = String(children??"");
  const wrapRef = useRef(null);
  const textRef = useRef(null);
  const [fontSize,setFontSize] = useState(max);
  const noWrap = oneLine ?? shouldKeepFitTextOnOneLine(text);

  useLayoutEffect(()=>{
    const wrap = wrapRef.current;
    const node = textRef.current;
    if(!wrap||!node) return;
    let frame = 0;
    const fit = ()=>{
      cancelAnimationFrame(frame);
      frame = requestAnimationFrame(()=>{
        const width = wrap.clientWidth;
        const height = wrap.clientHeight;
        if(!width||!height) return;
        let low = min;
        let high = max;
        let best = min;
        node.style.whiteSpace = noWrap ? "nowrap" : "normal";
        node.style.width = noWrap ? "auto" : `${width}px`;
        for(let i=0;i<9;i++){
          const mid = (low+high)/2;
          node.style.fontSize = `${mid}px`;
          if(node.scrollWidth<=width+1&&node.scrollHeight<=height+1){
            best = mid;
            low = mid;
          }else{
            high = mid;
          }
        }
        setFontSize(Math.floor(best*10)/10);
      });
    };
    fit();
    const observer = new ResizeObserver(fit);
    observer.observe(wrap);
    if(document?.fonts?.ready) document.fonts.ready.then(fit);
    return ()=>{
      cancelAnimationFrame(frame);
      observer.disconnect();
    };
  },[text,min,max,noWrap]);

  const boxClass = `fit-text-box ${noWrap?"fit-text-one-line":""} ${className}`;
  const content = <span ref={textRef} className="fit-text-content" style={{fontSize}}>{children}</span>;
  if(as==="span"){
    return (
      <span ref={wrapRef} className={boxClass} style={style}>
        {content}
      </span>
    );
  }
  return (
    <div ref={wrapRef} className={boxClass} style={style}>
      <span ref={textRef} className="fit-text-content" style={{fontSize}}>{children}</span>
    </div>
  );
}

