// ---- HOME ----
function HomeScreen({game,gameRecord,stats,onPlay,onNav}){
  const done=gameRecord?.completed;
  const mid=gameRecord&&!gameRecord.completed;
  return(
    <div>
      <div className="streak-row">
        {stats.currentStreak>0&&<span className="badge badge-orange"><FI name="flame" size={28} style={{marginRight:6}}/>{stats.currentStreak}-day streak</span>}
        {stats.bestCombo>=3&&<span className="badge badge-purple"><LightningMark size={18} style={{marginRight:6}}/>Best combo: {stats.bestCombo}x</span>}
      </div>
      <div className="card" style={{position:"relative",overflow:"hidden"}}>
        {game.headerImage&&(
          <div className="game-header-img-wrap">
            <img src={game.headerImage} alt={game.themeTitle} className="game-header-img" onError={e=>e.target.style.display="none"}/>
          </div>
        )}
        {!game.headerImage&&<div style={{position:"absolute",top:-8,right:14,fontSize:32,transform:"rotate(15deg)",filter:"drop-shadow(2px 3px 0 var(--teal-dark))",color:"var(--teal)"}}>🍬</div>}
        <div className="theme-lbl">Today's Theme</div>
        <div className="theme-title">{game.themeTitle}</div>
        <div className="vs-strip">
          <FitText as="span" className="cat-chip cat-a" min={10} max={13} oneLine={true}>{game.categoryA}</FitText>
          <span className="vs-word">VS</span>
          <FitText as="span" className="cat-chip cat-b" min={10} max={13} oneLine={true}>{game.categoryB}</FitText>
        </div>
        <div className="theme-count">{game.questions.length} questions · which is which??</div>
        {done?(
          <>
            <div style={{textAlign:"center",padding:"14px 0",borderTop:"2px dashed rgba(45,212,191,0.3)",marginBottom:14}}>
              <div style={{fontFamily:"'Fredoka One',cursive",fontSize:12,color:"var(--teal-dark)",letterSpacing:1,textTransform:"uppercase",marginBottom:4}}>Today's Score</div>
              <div style={{fontFamily:"'Fredoka One',cursive",fontSize:54,color:"var(--pink)",WebkitTextStroke:"2px var(--black)",textShadow:"3px 3px 0 var(--pink-dark)",lineHeight:1}}>
                {gameRecord.score}<span style={{fontSize:26,color:"var(--black)",WebkitTextStroke:"1px var(--black)",textShadow:"none"}}>/{gameRecord.totalQuestions}</span>
              </div>
            </div>
            <button className="btn btn-pink" onClick={()=>onNav("score")}>See my result 🎉</button>
          </>
        ):(
          <button className="btn btn-yellow" onClick={onPlay}>{mid?"Keep going!! →":"Let's gooo!! →"}</button>
        )}
      </div>
      <div className="btn-row">
        <button className="btn-nav-tile tile-teal" onClick={()=>onNav("stats")}>
          <FI name="chart" size={150}/>
          <span className="btn-nav-tile-lbl">Stats</span>
        </button>
        <button className="btn-nav-tile tile-orange" onClick={()=>onNav("archive")}>
          <FI name="cal" size={120}/>
          <span className="btn-nav-tile-lbl">Archive</span>
        </button>
      </div>
    </div>
  );
}

// ---- GAME ----
function GameScreen({game,gameRecord:initRec,onAnswer,onComplete,onNav,sound,isReplay=false}){
  const[rec,setRec]=useState(initRec);
  const[phase,setPhase]=useState(initRec.completed?"question":initRec.currentIndex>=game.questions.length?"question":"question");
  const[chosen,setChosen]=useState(null);
  const[animBtn,setAnimBtn]=useState(null);
  const[reaction,setReaction]=useState(null);
  const[combo,setCombo]=useState(0);
  const{play}=sound;
  const{canvasRef,shoot}=useConfetti();
  const beatOpts=["🤔","🤔","🤔","😬"];
  const e_ref=useRef(beatOpts[Math.floor(Math.random()*beatOpts.length)]);

  const idx=rec.currentIndex;
  const qs=game.questions.map(q=>({...q,_catA:game.categoryA,_catB:game.categoryB}));
  const cq=qs[idx];
  const isLast=idx===qs.length-1;

  // Guard: once we've advanced past the last question, stop rendering question/reveal UI.
  if(!cq) return null;

  // Pick a fresh suspense emoji each time a new question starts
  useEffect(()=>{
    e_ref.current=beatOpts[Math.floor(Math.random()*beatOpts.length)];
  },[idx]);

  const handleAnswerClick=cat=>{
    const correct=cat===cq.correctCategory;
    setAnimBtn({cat,correct});
    setChosen(cat);

    const newCombo=correct?combo+1:0;
    setCombo(newCombo);
    if(correct){
      play(newCombo>=3?"combo":"correct");
      if(newCombo>=3)shoot("normal");
    } else {
      play("wrong");
    }

    setTimeout(()=>{setAnimBtn(null);setPhase("reveal");},300);
  };

  const handleNext=()=>{
    const correct=chosen===cq.correctCategory;
    const newAnswers=[...rec.answers,{questionIndex:idx,chosenCategory:chosen,correct}];
    const newScore=rec.score+(correct?1:0);
    const updated={...rec,answers:newAnswers,currentIndex:idx+1,score:newScore};
    setRec(updated);
    setChosen(null);

    // Sync to Supabase (fire and forget)
    if(!isReplay) onAnswer(game.date, newAnswers, newScore);

    if(isLast){
      const final={...updated,completed:true,completedAt:new Date().toISOString()};
      if(final.score===final.totalQuestions){play("perfect");shoot("perfect");}
      onComplete(final);
    } else {
      setPhase("question");
    }
  };

  return(
    <div>
      <canvas ref={canvasRef} id="confetti-canvas" style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:9999}}/>
      {reaction&&<ReactionOverlay emoji={reaction}/>}
      <div style={{marginBottom:8,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <button className="btn-sm" onClick={()=>onNav(isReplay?"archive":"home")}>← Back</button>
        <div style={{fontFamily:"'Fredoka One',cursive",fontSize:12,color:"var(--teal-dark)",opacity:.7,maxWidth:210,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
          {isReplay?"📼 Replay: ":""}{game.themeTitle}
        </div>
      </div>

      {isReplay&&(
        <div className="replay-banner">
          📼 Replay mode — scores not saved to your stats
        </div>
      )}

      <ProgressDots total={qs.length} currentIndex={idx} answers={rec.answers} combo={combo}/>

      {phase==="question"&&(
        <>
          <div className="q-card">
            <div className="q-deco">?</div>
            <div className="item-text">{cq.itemText}</div>
          </div>
          <div className="ans-btns" style={{marginTop:10}}>
            {[
              {cat:"A",label:cq._catA,img:game.categoryAImage,color:PALETTE.find(p=>p.id===(game.categoryAColor||"teal"))||PALETTE[0]},
              {cat:"B",label:cq._catB,img:game.categoryBImage,color:PALETTE.find(p=>p.id===(game.categoryBColor||"pink"))||PALETTE[1]}
            ].map(({cat,label,img,color})=>{
              let boxCls="ans-box";
              if(animBtn?.cat===cat) boxCls+=animBtn.correct?" correct":" wrong";
              else if(animBtn) boxCls+=" dis";
              const isDark=color.isDark;
              return(
                <button key={cat} className={boxCls}
                  style={{
                    background:`linear-gradient(160deg,${color.light} 0%,${color.mid} 55%,${color.dark} 100%)`,
                    borderColor:color.dark
                  }}
                  onClick={()=>!animBtn&&handleAnswerClick(cat)}>
                  {img ? (
                    <div className="ans-box-img-wrap">
                      <img src={img} alt={label} className="ans-box-img"/>
                    </div>
                  ) : (
                    <div className="ans-box-img-placeholder" style={{background:`linear-gradient(160deg,${color.light} 0%,${color.mid} 100%)`}}>
                      {cat==="A"?"🎲":"🎬"}
                    </div>
                  )}
                  <FitText className="ans-box-label" min={18} max={48} style={{color:isDark?"white":"var(--black)",textShadow:isDark?"1px 2px 0 rgba(0,0,0,0.2)":"none",WebkitTextStroke:isDark?"0.5px rgba(0,0,0,0.2)":"0"}}>
                    {label}
                  </FitText>
                </button>
              );
            })}
          </div>
        </>
      )}

      {phase==="beat"&&(
        <>
          <div className="q-card">
            <div className="item-text">{cq.itemText}</div>
          </div>
          <div className="beat-overlay">
            <span className="beat-emoji-pop">{e_ref.current}</span>
          </div>
        </>
      )}

      {phase==="reveal"&&(
        <div className="reveal-card">
          {/* Image zone — 60% */}
          {cq.imageUrl ? (
            <div className="reveal-img-zone">
              {getYouTubeEmbedUrl(cq.imageUrl)?(
                <iframe className="reveal-video" src={getYouTubeEmbedUrl(cq.imageUrl)} title={cq.imageAlt||cq.itemText} allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" allowFullScreen/>
              ):(
                <img src={cq.imageUrl} alt={cq.imageAlt||cq.itemText} className="reveal-img"/>
              )}
              {cq.imageSource&&(
                <div className="reveal-img-overlay">
                  <div className="img-source" style={{color:"rgba(255,255,255,.7)"}}>📷 {cq.imageSource}</div>
                </div>
              )}
            </div>
          ) : (
            <div className="reveal-placeholder">
              {chosen===cq.correctCategory?<FI name="trophy" size={80}/>:"💀"}
            </div>
          )}

          {/* Text zone — 40% */}
          <div className="reveal-text-zone">
            <div className={`verdict-bar ${chosen===cq.correctCategory?"ok":"no"}`}>
              <span style={{fontSize:20}}>{chosen===cq.correctCategory?"🎉":"😬"}</span>
              {chosen===cq.correctCategory?"Correct!!":"Nope!!"}&nbsp;
              <span style={{fontSize:14,opacity:.85}}>It's a <strong>{cq.correctCategory==="A"?cq._catA:cq._catB}</strong>!</span>
            </div>
            {cq.flavorCopy&&<div className="flavor-box">"{cq.flavorCopy}"</div>}
            {cq.explanationCopy&&<div className="expl-box">{cq.explanationCopy}</div>}
            <button className={`btn ${chosen===cq.correctCategory?"btn-green":"btn-pink"}`} onClick={handleNext}>
              {isLast?"See my score!! →":"Next →"}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

// ---- SCORE ----
function ScoreScreen({gameRecord,game,onNav,sound,isReplay=false}){
  const safeRecord = {
    themeTitle: gameRecord?.themeTitle||"Puzzle Results",
    score: Number.isFinite(gameRecord?.score) ? gameRecord.score : 0,
    totalQuestions: Number.isFinite(gameRecord?.totalQuestions) ? gameRecord.totalQuestions : 0,
    answers: Array.isArray(gameRecord?.answers) ? gameRecord.answers : [],
    date: gameRecord?.date||null
  };
  const[copied,setCopied]=useState(false);
  const[animKey,setAnimKey]=useState(0);
  const[communityStats,setCommunityStats]=useState(null);
  const[showAdvanced,setShowAdvanced]=useState(false);
  const{play}=sound;
  const{canvasRef,shoot}=useConfetti();
  const isPerfect=safeRecord.totalQuestions>0&&safeRecord.score===safeRecord.totalQuestions;

  useEffect(()=>{
    if(isPerfect){play("perfect");shoot("perfect");}
  },[]);

  // Replay the dot animation every 3s while idle
  useEffect(()=>{
    const id=setInterval(()=>setAnimKey(k=>k+1), 3000);
    return()=>clearInterval(id);
  },[]);

  useEffect(()=>{
    let cancelled = false;
    (async()=>{
      if(!safeRecord.date) return;
      const stats = await dbGetPuzzleCommunityStats(safeRecord.date, safeRecord.score);
      if(!cancelled) setCommunityStats(stats);
    })();
    return ()=>{cancelled = true;};
  },[safeRecord.date, safeRecord.score]);

  const txt=buildShare(safeRecord);
  const share=()=>{try{navigator.clipboard.writeText(txt);}catch{}setCopied(true);setTimeout(()=>setCopied(false),2000);};

  return(
    <div>
      <canvas ref={canvasRef} id="confetti-canvas-score" style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:9999}}/>
      <div className="score-card">
        {isReplay&&<div style={{background:"linear-gradient(160deg,#5EEAD4,#2DD4BF 55%,#0F9488)",color:"var(--black)",fontFamily:"'Fredoka One',cursive",fontSize:13,padding:"8px 16px",borderRadius:16,marginBottom:12,border:"2.5px solid var(--teal-dark)",boxShadow:"0 4px 0 var(--teal-dark)",position:"relative"}}>📼 Replay — not saved to your stats</div>}
        <div className="score-theme-tag">🍬 {safeRecord.themeTitle}</div>

        {isPerfect&&(
          <div className="perfect-banner">
            <div className="perfect-title"><FI name="trophy" size={44} style={{marginRight:10}}/>PERFECT SCORE!!</div>
            <div className="perfect-sub">Every single one. You absolute legend.</div>
          </div>
        )}

        <div className="score-big">
          {safeRecord.score}<span className="score-denom">/{safeRecord.totalQuestions}</span>
        </div>
        <div className="score-sublbl">questions correct</div>
        <div className="score-msg">{scoreMsg(safeRecord.score,safeRecord.totalQuestions||1)}</div>

        <div className="emoji-grid" key={animKey}>
          {safeRecord.answers.map((a,i)=>(
            <div key={i} className={`emoji-cell ${a.correct?'correct-dot':'wrong-dot'}`} style={{animationDelay:`${i*65}ms`}}/>
          ))}
        </div>

        {!isReplay&&<><div className="share-box">{txt}</div>
        <button className="btn btn-pink" onClick={share} style={{marginBottom:10}}>
          {copied?"✓ Copied to clipboard!!":"Copy & Share 📋"}
        </button></>}

        <div className="results-jazz">
          <div className="results-marquee">
            <div className="results-marquee-top">Game Show Recap</div>
            <div className="results-marquee-main">
              {isPerfect?"Jackpot round cleared!!":"Scoreboard drama delivered!!"}
            </div>
          </div>
        </div>

        {communityStats&&(
          <div className="crowd-wrap">
            <div className="crowd-head">
              <div className="crowd-title">How The Crowd Survived</div>
              <div className="crowd-chip">{communityStats.finishedPlayers} player{communityStats.finishedPlayers===1?"":"s"}</div>
            </div>
            {communityStats.finishedPlayers<10&&(
              <div className="crowd-warning">
                You are one of the first players, so these stats may change. Come back later for more accurate results!
              </div>
            )}
            <div className="crowd-grid">
              <div className="crowd-stat crowd-stat-avg">
                <div className="crowd-stat-kicker">Average Chaos</div>
                <div className="crowd-stat-main">{averageScoreCopy(communityStats.averageScore, safeRecord.totalQuestions)}</div>
              </div>
              <div className="crowd-stat crowd-stat-beat">
                <div className="crowd-stat-kicker">Crowd Showdown</div>
                <div className="crowd-stat-main">{beatRateCopy(communityStats.beatRate)}</div>
              </div>
              <div className="crowd-stat crowd-stat-perfect">
                <div className="crowd-stat-kicker">Perfect Goblins</div>
                <div className="crowd-stat-main">{perfectRateCopy(communityStats.perfectRate)}</div>
              </div>
            </div>
            <div className="crowd-foot">Only finished first attempts count. Replays do not mess with the scoreboard.</div>
            <button className="btn-sm advanced-toggle" onClick={()=>setShowAdvanced(v=>!v)}>
              {showAdvanced?"Hide Nerd Mode":"Show Nerd Mode"}
            </button>
            {showAdvanced&&(
              <div className="advanced-panel">
                {(Array.isArray(communityStats.questionAccuracies)?communityStats.questionAccuracies:[]).map((q,idx)=>(
                  <div key={q.index} className="advanced-card">
                    <div className="advanced-card-top">Question {idx+1}</div>
                    <div className="advanced-card-title">{game?.questions?.[idx]?.itemText||"Accuracy"}</div>
                    <div className="advanced-card-sub">{q.correctRate}% of players got it right</div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        <button className="btn btn-yellow" onClick={()=>onNav(isReplay?"archive":"home")}>
          {isReplay?"← Back to archive":"← Back to home"}
        </button>

        {!isReplay&&<Countdown/>}
      </div>
    </div>
  );
}

// ---- STATS ----
function StatsScreen({stats,onNav}){
  const s=stats;
  const pct=s.totalQuestions>0?Math.round(s.totalCorrect/s.totalQuestions*100):0;
  return(
    <div>
      <div className="sec-head"><FI name="chart" size={52} style={{marginRight:10,verticalAlign:"middle"}}/>Your Stats</div>
      <div className="sec-sub">All stored on this device. Play every day!</div>
      <div className="card">
        <div className="stats-grid">
          <div className="stat-tile"><div className="stat-val"><FI name="flame" size={64} style={{marginBottom:4}}/><br/>{s.currentStreak}</div><div className="stat-lbl">Streak</div></div>
          <div className="stat-tile"><div className="stat-val">{s.longestStreak}</div><div className="stat-lbl">Best Streak</div></div>
          <div className="stat-tile"><div className="stat-val">{s.totalPlayed}</div><div className="stat-lbl">Games</div></div>
          <div className="stat-tile"><div className="stat-val">{pct}%</div><div className="stat-lbl">Accuracy</div></div>
          <div className="stat-tile"><div className="stat-val"><LightningMark size={34} style={{marginRight:6}}/>{s.bestCombo}x</div><div className="stat-lbl">Best Combo Streak</div></div>
        </div>
      </div>
      <div style={{marginTop:12}}><button className="btn-sm" onClick={()=>onNav("home")}>← Back</button></div>
    </div>
  );
}

// ---- ARCHIVE (with replay) ----
function ArchiveScreen({games,playerId,onNav,onReplay}){
  const sorted=[...games].filter(g=>g.status==="published").sort((a,b)=>b.date.localeCompare(a.date));
  const today=getLocalGameDay();
  const[records,setRecords]=useState({});

  useEffect(()=>{
    if(!playerId||!sorted.length) return;
    (async()=>{
      const recs={};
      await Promise.all(sorted.map(async g=>{
        const r = await dbGetGameRecord(playerId, g.date);
        if(r) recs[g.date]=r;
      }));
      setRecords(recs);
    })();
  },[playerId, games.length]);

  return(
    <div>
      <div className="sec-head"><FI name="cal" size={52} style={{marginRight:10,verticalAlign:"middle"}}/>Archive</div>
      <div className="sec-sub">Every theme ever. Tap any past game to replay it!</div>
      <div className="card">
        {sorted.length===0&&<div style={{textAlign:"center",color:"#aaa",padding:"24px 0",fontFamily:"'Fredoka One',cursive"}}>No games yet!</div>}
        {sorted.map(g=>{
          const r=records[g.date];
          const isToday=g.date===today;
          const canReplay=!isToday&&g.questions?.length>0;
          return(
            <div
              className={`archive-row${isToday?" today-row":""}`}
              key={g.date}
              onClick={()=>canReplay&&onReplay(g)}
              style={{cursor:canReplay?"pointer":"default"}}
            >
              {g.headerImage&&<img src={g.headerImage} alt={g.themeTitle} className="archive-thumb" onError={e=>e.target.style.display="none"}/>}
              <div>
                <div className="archive-date">{isToday?"Today":new Date(g.date+"T12:00:00").toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"})}</div>
                <div className="archive-theme">{g.themeTitle}</div>
              </div>
              <div className="archive-right">
                {r?.completed&&(
                  <div className={`score-pill${r.score===r.totalQuestions?" perfect":""}`}>{r.score}/{r.totalQuestions}</div>
                )}
                {isToday&&<div className="today-chip">Today</div>}
                {canReplay&&<div className="replay-chip">▶ Replay</div>}
              </div>
            </div>
          );
        })}
      </div>
      <div style={{marginTop:12}}><button className="btn-sm" onClick={()=>onNav("home")}>← Back</button></div>
    </div>
  );
}

function AccountScreen({player,onNav,onUpgrade,onMagicLink,onSignOut,authBusy,authMode}){
  const[email,setEmail]=useState(player?.email||"");
  const guest = player?.isGuest;
  const isCreating = authBusy&&authMode==="create";
  const isMagicLink = authBusy&&authMode==="magic";
  const isSigningOut = authBusy&&authMode==="signout";

  const submitUpgrade=()=>{
    const trimmed = email.trim();
    if(trimmed) onUpgrade(trimmed);
  };
  const submitMagic=()=>{
    const trimmed = email.trim();
    if(trimmed) onMagicLink(trimmed);
  };

  return(
    <div>
      <div className="sec-head">Account</div>
      <div className="sec-sub">Play as a guest first, then lock in your streak whenever you want.</div>
      <div className="card">
        <div style={{display:"inline-flex",alignItems:"center",gap:6,fontFamily:"'Fredoka One',cursive",fontSize:12,padding:"6px 14px",borderRadius:999,border:"2px solid var(--black)",boxShadow:"var(--shadow-sm)",background:guest?"linear-gradient(180deg,#FFF176 0%,#FFE347 55%,#E6C800 100%)":"linear-gradient(180deg,#C084FC 0%,#A855F7 55%,#7E22CE 100%)",color:guest?"var(--black)":"white",marginBottom:14}}>
          {guest?"Guest Mode":"Account Ready"}
        </div>
        <div style={{fontSize:14,fontWeight:800,color:"var(--black)",marginBottom:8}}>
          {guest?"You're playing as a guest right now.":"You're signed in and your progress can follow you across devices."}
        </div>
        <div style={{fontSize:13,fontWeight:700,color:"#666",lineHeight:1.5,marginBottom:16}}>
          {guest?"Save this guest profile to an email so you can keep your streak across devices.":"Magic links let you hop back into this same account without a password."}
        </div>

        <div className="adm-field" style={{marginBottom:12}}>
          <label>Email</label>
          <input className="adm-input" value={email} placeholder="you@example.com" onChange={e=>setEmail(e.target.value)} onKeyDown={e=>e.key==="Enter"&&submitUpgrade()}/>
        </div>

        {guest?(
          <>
            <button className="btn btn-yellow" onClick={submitUpgrade} disabled={authBusy||!email.trim()} style={{marginBottom:10}}>
              {isUpgrading?"Sending guest-save email...":"Save This Guest To My Email"}
            </button>
            <div style={{fontSize:12,fontWeight:800,color:"rgba(26,26,26,.65)",marginBottom:16}}>
              We'll send a confirmation email that saves this guest progress to that address. It does not set or change a password.
            </div>
            <div style={{borderTop:"2px dashed rgba(45,212,191,0.3)",paddingTop:14}}>
              <div style={{fontFamily:"'Fredoka One',cursive",fontSize:13,color:"var(--teal-dark)",marginBottom:8}}>Already have an account?</div>
              <button className="btn btn-teal" onClick={submitMagic} disabled={authBusy||!email.trim()}>
                {isMagicLink?"Sending magic link..." :"Email Me A Magic Link"}
              </button>
              <div style={{fontSize:12,fontWeight:800,color:"rgba(26,26,26,.65)",marginTop:10}}>
                Use this if that email already has a trivia account and you want to sign back into it.
              </div>
            </div>
          </>
        ):(
          <>
            <div style={{fontSize:14,fontWeight:900,color:"var(--black)",marginBottom:14}}>{player?.email||"Signed in"}</div>
            <button className="btn btn-pink" onClick={onSignOut} disabled={authBusy}>
              {isSigningOut?"Switching to guest mode..." :"Sign Out To Guest Mode"}
            </button>
          </>
        )}
      </div>
      <div style={{marginTop:12}}><button className="btn-sm" onClick={()=>onNav("home")}>← Back</button></div>
    </div>
  );
}

function AccountScreenV2({player,onNav,onCreateAccount,onPasswordSignIn,onMagicLink,onSignOut,authBusy,authMode}){
  const[email,setEmail]=useState(player?.email||"");
  const[password,setPassword]=useState("");
  const[accountMode,setAccountMode]=useState("signin");
  const guest = player?.isGuest;
  const isCreating = authBusy&&authMode==="create";
  const isPasswordSignIn = authBusy&&authMode==="password";
  const isMagicLink = authBusy&&authMode==="magic";
  const isSigningOut = authBusy&&authMode==="signout";

  const submitCreate=()=>{
    const trimmed = email.trim();
    if(trimmed&&password.trim()) onCreateAccount(trimmed,password);
  };
  const submitPasswordSignIn=()=>{
    const trimmed = email.trim();
    if(trimmed&&password.trim()) onPasswordSignIn(trimmed,password);
  };
  const submitEmailLink=()=>{
    const trimmed = email.trim();
    if(trimmed) onMagicLink(trimmed);
  };

  return(
    <div>
      <div className="sec-head">{guest?"Sign In":"Account"}</div>
      <div className="sec-sub">{guest?"Sign in to save your streak and sync it across devices.":"You're signed in, so your stats can follow you across devices."}</div>
      <div className="card">
        {guest?(
          <div style={{maxWidth:430,margin:"0 auto",textAlign:"center"}}>
            <div style={{display:"inline-flex",alignItems:"center",gap:6,fontFamily:"'Fredoka One',cursive",fontSize:12,padding:"6px 14px",borderRadius:999,border:"2px solid var(--black)",boxShadow:"var(--shadow-sm)",background:"linear-gradient(180deg,#FFF176 0%,#FFE347 55%,#E6C800 100%)",color:"var(--black)",marginBottom:16}}>
              Not Signed In
            </div>
            <div style={{fontFamily:"'Fredoka One',cursive",fontSize:32,lineHeight:1.15,color:"var(--black)",marginBottom:14}}>
              Save your stats
              <br/>
              with an account
            </div>
            <div style={{fontSize:14,fontWeight:700,color:"#666",lineHeight:1.6,margin:"0 auto 18px",maxWidth:380}}>
              Use your email and password to sign in or create an account. Your streak and stats will sync anywhere you're signed in.
            </div>
            <div style={{display:"flex",gap:8,marginBottom:12}}>
              <button className={`btn ${accountMode==="signin"?"btn-teal":"btn-pink"}`} style={{flex:1,fontSize:16}} onClick={()=>setAccountMode("signin")}>
                Sign In
              </button>
              <button className={`btn ${accountMode==="create"?"btn-yellow":"btn-pink"}`} style={{flex:1,fontSize:16}} onClick={()=>setAccountMode("create")}>
                Create Account
              </button>
            </div>
            <input
              className="adm-input"
              value={email}
              placeholder="Email address"
              onChange={e=>setEmail(e.target.value)}
              onKeyDown={e=>e.key==="Enter"&&(accountMode==="create"?submitCreate():submitPasswordSignIn())}
              style={{textAlign:"center",fontSize:18,fontWeight:900,padding:"18px 16px",marginBottom:12}}
            />
            <input
              className="adm-input"
              type="password"
              value={password}
              placeholder={accountMode==="create"?"Create a password":"Password"}
              onChange={e=>setPassword(e.target.value)}
              onKeyDown={e=>e.key==="Enter"&&(accountMode==="create"?submitCreate():submitPasswordSignIn())}
              style={{textAlign:"center",fontSize:18,fontWeight:900,padding:"18px 16px",marginBottom:12}}
            />
            <button
              className={`btn ${accountMode==="create"?"btn-yellow":"btn-teal"}`}
              onClick={accountMode==="create"?submitCreate:submitPasswordSignIn}
              disabled={authBusy||!email.trim()||!password.trim()}
              style={{fontSize:24,marginBottom:12}}
            >
              {accountMode==="create"
                ? (isCreating?"Creating account...":"Create Account")
                : (isPasswordSignIn?"Signing in...":"Sign In")}
            </button>
            <div style={{fontSize:12,fontWeight:800,color:"rgba(26,26,26,.65)",lineHeight:1.5,marginBottom:18}}>
              {accountMode==="create"
                ? "New accounts start here. We can add smarter device-progress carryover next."
                : "If you already have an account, sign in here with your email and password."}
            </div>
            <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:16}}>
              <div style={{flex:1,height:2,background:"rgba(26,26,26,.12)"}}/>
              <div style={{fontFamily:"'Fredoka One',cursive",fontSize:13,color:"rgba(26,26,26,.55)"}}>email link</div>
              <div style={{flex:1,height:2,background:"rgba(26,26,26,.12)"}}/>
            </div>
            <button className="btn btn-pink" onClick={submitEmailLink} disabled={authBusy||!email.trim()} style={{marginBottom:10}}>
              {isMagicLink?"Sending magic link..." :"Continue with existing account"}
            </button>
            <div style={{fontSize:12,fontWeight:800,color:"rgba(26,26,26,.65)",lineHeight:1.5}}>
              Prefer not to type a password? We'll email you a sign-in link instead.
            </div>
          </div>
        ):(
          <div style={{maxWidth:430,margin:"0 auto",textAlign:"center"}}>
            <div style={{display:"inline-flex",alignItems:"center",gap:6,fontFamily:"'Fredoka One',cursive",fontSize:12,padding:"6px 14px",borderRadius:999,border:"2px solid var(--black)",boxShadow:"var(--shadow-sm)",background:"linear-gradient(180deg,#C084FC 0%,#A855F7 55%,#7E22CE 100%)",color:"white",marginBottom:16}}>
              Signed In
            </div>
            <div style={{fontFamily:"'Fredoka One',cursive",fontSize:30,lineHeight:1.15,color:"var(--black)",marginBottom:14}}>
              Your stats are
              <br/>
              locked in
            </div>
            <div style={{fontSize:14,fontWeight:700,color:"#666",lineHeight:1.6,margin:"0 auto 18px",maxWidth:360}}>
              You're signed in as <strong style={{color:"var(--black)"}}>{player?.email||"this account"}</strong>. Your progress can now follow you across devices.
            </div>
            <button className="btn btn-pink" onClick={onSignOut} disabled={authBusy} style={{marginBottom:10}}>
              {isSigningOut?"Signing out..." :"Sign Out"}
            </button>
            <div style={{fontSize:12,fontWeight:800,color:"rgba(26,26,26,.65)",lineHeight:1.5}}>
              After signing out, you can still play on this device without being signed in.
            </div>
          </div>
        )}
      </div>
      <div style={{marginTop:12}}><button className="btn-sm" onClick={()=>onNav("home")}>{"<- Back"}</button></div>
    </div>
  );
}

