function AdminDatePicker({value,onChange,games,currentGameId}){
  const selectedDate = localDateFromISO(value) || new Date();
  const[month,setMonth]=useState(()=>new Date(selectedDate.getFullYear(), selectedDate.getMonth(), 1));
  const[draft,setDraft]=useState(()=>formatAdminDate(value));
  const[open,setOpen]=useState(true);
  const occupied = new Map();
  (games||[]).forEach(g=>{
    if(g?.date) occupied.set(g.date,g);
  });
  const conflict = value ? occupied.get(value) : null;
  const hasConflict = Boolean(conflict && conflict.id!==currentGameId);
  const ownDate = Boolean(conflict && conflict.id===currentGameId);
  const monthTitle = month.toLocaleDateString("en-US",{month:"long",year:"numeric"});
  const firstDay = new Date(month.getFullYear(), month.getMonth(), 1);
  const daysInMonth = new Date(month.getFullYear(), month.getMonth()+1, 0).getDate();
  const blanks = Array.from({length:firstDay.getDay()},(_,i)=>({empty:true,key:`b-${i}`}));
  const days = Array.from({length:daysInMonth},(_,idx)=>{
    const day = idx+1;
    const date = new Date(month.getFullYear(), month.getMonth(), day);
    const iso = isoFromLocalDate(date);
    const game = occupied.get(iso);
    return {day,iso,game};
  });
  const cells = [...blanks,...days];
  const shiftMonth = delta => setMonth(m=>new Date(m.getFullYear(), m.getMonth()+delta, 1));
  const chooseDate = iso => {
    const game = occupied.get(iso);
    if(game && game.id!==currentGameId) return;
    onChange(iso);
    setDraft(formatAdminDate(iso));
  };
  const applyDraft = () => {
    const parsed = parseAdminDate(draft);
    if(parsed){
      onChange(parsed);
      setDraft(formatAdminDate(parsed));
      const parsedDate = localDateFromISO(parsed);
      if(parsedDate) setMonth(new Date(parsedDate.getFullYear(), parsedDate.getMonth(), 1));
    }else if(!draft.trim()){
      onChange("");
    }else{
      setDraft(formatAdminDate(value));
    }
  };
  useEffect(()=>{
    setDraft(formatAdminDate(value));
    const date = localDateFromISO(value);
    if(date) setMonth(new Date(date.getFullYear(), date.getMonth(), 1));
  },[value]);

  return(
    <div className="admin-date-picker">
      <div className="adm-field" style={{marginBottom:0}}>
        <label>Puzzle Date (MM/DD/YYYY)</label>
        <div className="admin-date-top">
          <div className="admin-date-input-wrap">
            <input
              className="adm-input"
              value={draft}
              placeholder="04/30/2026"
              onChange={e=>setDraft(e.target.value)}
              onBlur={applyDraft}
              onKeyDown={e=>e.key==="Enter"&&applyDraft()}
            />
          </div>
          <button type="button" className="btn-adm admin-date-btn" onClick={()=>setOpen(v=>!v)}>
            {open?"Hide":"Calendar"}
          </button>
        </div>
      </div>
      {hasConflict&&(
        <div className="admin-date-note bad">
          {formatAdminDate(value)} already has "{conflict.themeTitle||"another puzzle"}". Pick a different day.
        </div>
      )}
      {!hasConflict&&value&&(
        <div className={`admin-date-note ${ownDate?"good":""}`}>
          {ownDate?"This is this puzzle's current day.":"This day is available."}
        </div>
      )}
      {open&&(
        <div className="admin-calendar">
          <div className="admin-cal-head">
            <div className="admin-cal-title">{monthTitle}</div>
            <div className="admin-cal-nav">
              <button type="button" onClick={()=>shiftMonth(-1)}>‹</button>
              <button type="button" onClick={()=>setMonth(new Date())}>Today</button>
              <button type="button" onClick={()=>shiftMonth(1)}>›</button>
            </div>
          </div>
          <div className="admin-cal-grid">
            {["Sun","Mon","Tue","Wed","Thu","Fri","Sat"].map(d=><div key={d} className="admin-cal-dow">{d}</div>)}
            {cells.map(cell=>{
              if(cell.empty) return <div key={cell.key} className="admin-cal-day empty"/>;
              const cellGame = cell.game;
              const isOwn = cellGame?.id===currentGameId;
              const isUsed = Boolean(cellGame && !isOwn);
              const selected = cell.iso===value;
              const cls = `admin-cal-day ${selected?"selected":""} ${isUsed?"occupied":""} ${isOwn?"own":""}`;
              return(
                <button
                  type="button"
                  key={cell.iso}
                  className={cls}
                  onClick={()=>chooseDate(cell.iso)}
                  title={cellGame?`${formatAdminDate(cell.iso)}: ${cellGame.themeTitle}`:formatAdminDate(cell.iso)}
                >
                  <span>{cell.day}</span>
                  {cellGame&&<span className="admin-cal-status">{isOwn?"This":cellGame.status||"Used"}</span>}
                </button>
              );
            })}
          </div>
          <div className="admin-cal-legend">
            <span><span className="admin-cal-dot used"/>Day already has a puzzle</span>
            <span><span className="admin-cal-dot mine"/>This puzzle's day</span>
          </div>
        </div>
      )}
    </div>
  );
}

function AdminEditor({game:ig,games,onSave,onDelete,onBack}){
  const isNew=!ig.id;
  const[game,setGame]=useState(()=>loadEditorDraft(ig));
  const[showQF,setShowQF]=useState(false);
  const[editQ,setEditQ]=useState(null);
  const[dragQId,setDragQId]=useState(null);
  const[dragOverQId,setDragOverQId]=useState(null);
  const[toast,setToast]=useState(null);
  const[preview,setPreview]=useState(false);
  const[autoSaveState,setAutoSaveState]=useState("idle");
  const[lastAutoSavedAt,setLastAutoSavedAt]=useState(()=>safeRead(getEditorDraftKey(ig.id))?.savedAt||null);
  const st=(m,ms=2100)=>{setToast(m);setTimeout(()=>setToast(null),ms);};
  const set=(f,v)=>setGame(g=>({...g,[f]:v}));
  const qc=game.questions?.length??0;
  const ok=qc>=4&&qc<=15;
  const dateConflict = game.date ? (games||[]).find(g=>g.date===game.date&&g.id!==game.id) : null;
  const dateOk = Boolean(localDateFromISO(game.date)) && !dateConflict;
  const canPublish = ok && dateOk;
  const validateDate = () => {
    if(!localDateFromISO(game.date)){st("Pick a puzzle date first.");return false;}
    if(dateConflict){st(`That day already has "${dateConflict.themeTitle||"another puzzle"}".`);return false;}
    return true;
  };

  useEffect(()=>{
    const restored = loadEditorDraft(ig);
    setGame(restored);
    setShowQF(false);
    setEditQ(null);
    setAutoSaveState("idle");
    setLastAutoSavedAt(safeRead(getEditorDraftKey(ig.id))?.savedAt||null);
  },[ig]);

  useEffect(()=>{
    if(!game?.id) return;
    if(game.status==="published"){
      clearEditorDraft(game.id);
      setLastAutoSavedAt(null);
      setAutoSaveState("idle");
      return;
    }
    setAutoSaveState("saving");
    const timer = setTimeout(()=>{
      if(saveEditorDraft(game)){
        setLastAutoSavedAt(Date.now());
        setAutoSaveState("saved");
      }
    }, 700);
    return ()=>clearTimeout(timer);
  },[game]);

  const pub=async()=>{if(!validateDate())return;if(!ok){st(`Need 4–15 questions (have ${qc})`);return;}const s={...game,status:"published"};st("Publishing + archiving images... ⏳",8000);try{const saved=await onSave(s);clearEditorDraft((saved||s).id);setGame(saved||s);setLastAutoSavedAt(null);setAutoSaveState("idle");}catch(e){st(e?.message||"Save failed 😬",6000);}};
  const dft=async()=>{if(!validateDate())return;const s={...game,status:game.status==="published"?"published":"draft"};if(!s.id)s.id=`g-${Date.now()}`;if(!s.questions)s.questions=[];st("Saving... ⏳");try{const saved=await onSave(s);clearEditorDraft((saved||s).id);setGame(saved||s);setLastAutoSavedAt(null);setAutoSaveState("idle");}catch(e){st(e?.message||"Save failed 😬",6000);}};
  const pubSafe=async()=>{if(!validateDate())return;await pub();};
  const dftSafe=async()=>{if(!validateDate())return;await dft();};
  const addQ=q=>{setGame(g=>({...g,questions:[...(g.questions??[]),{...q,id:`q-${Date.now()}`,orderIndex:(g.questions?.length??0)+1}]}));setShowQF(false);setEditQ(null);};
  const updQ=u=>setGame(g=>({...g,questions:g.questions.map(q=>q.id===u.id?u:q)}));
  const delQ=q=>{
    if(!window.confirm(`Delete "${q.itemText||"this question"}"?`)) return;
    setEditQ(e=>e?.id===q.id?null:e);
    setGame(g=>({...g,questions:g.questions.filter(item=>item.id!==q.id).map((item,i)=>({...item,orderIndex:i+1}))}));
  };
  const reorderQ=(fromId,toId)=>setGame(g=>{
    if(!fromId||!toId||fromId===toId) return g;
    const list = [...(g.questions||[])];
    const from = list.findIndex(q=>q.id===fromId);
    const to = list.findIndex(q=>q.id===toId);
    if(from<0||to<0) return g;
    const [moved] = list.splice(from,1);
    list.splice(to,0,moved);
    return {...g,questions:list.map((q,i)=>({...q,orderIndex:i+1}))};
  });
  const startDrag=(e,id)=>{setDragQId(id);setDragOverQId(null);e.dataTransfer.effectAllowed="move";e.dataTransfer.setData("text/plain",id);};
  const overDrag=(e,id)=>{e.preventDefault();if(id!==dragOverQId)setDragOverQId(id);};
  const dropDrag=(e,id)=>{e.preventDefault();const from=e.dataTransfer.getData("text/plain")||dragQId;reorderQ(from,id);setDragQId(null);setDragOverQId(null);};
  const endDrag=()=>{setDragQId(null);setDragOverQId(null);};

  if(preview)return <AdminPreview game={game} onBack={()=>setPreview(false)}/>;

  return(
    <div className="adm-shell">
      <div className="adm-hdr">
        <div className="adm-title">{isNew?"New Game":"Edit Game"}</div>
        <div style={{display:"flex",gap:7}}>
          <button className="btn-adm btn-adm-g" onClick={()=>setPreview(true)}>Preview</button>
          <button className="btn-adm btn-adm-g" onClick={onBack}>← Back</button>
        </div>
      </div>
      <div className="adm-body">
        <div className="adm-card">
          <h3>Game Details</h3>
          <div style={{fontSize:11,fontWeight:800,color:"rgba(255,255,255,.6)",marginBottom:10}}>
            {autoSaveState==="saving"?"Auto-saving draft...":lastAutoSavedAt?`Draft auto-saved locally at ${new Date(lastAutoSavedAt).toLocaleTimeString([], {hour:"numeric",minute:"2-digit"})}`:"Draft auto-save is on"}
          </div>
          <AdminDatePicker value={game.date||""} onChange={v=>set("date",v)} games={games} currentGameId={game.id}/>
          <div className="adm-field"><label>Theme Title</label><input className="adm-input" value={game.themeTitle||""} placeholder="Board Game or Nicolas Cage Movie?" onChange={e=>set("themeTitle",e.target.value)}/></div>
          <div style={{display:"flex",gap:9}}>
            <div className="adm-field" style={{flex:1}}><label>Category A</label><input className="adm-input" value={game.categoryA||""} placeholder="Board Game" onChange={e=>set("categoryA",e.target.value)}/></div>
            <div className="adm-field" style={{flex:1}}><label>Category B</label><input className="adm-input" value={game.categoryB||""} placeholder="Nicolas Cage Movie" onChange={e=>set("categoryB",e.target.value)}/></div>
          </div>
          <div style={{display:"flex",gap:9}}>
            <div style={{flex:1}}>
              <ImageUploader label={`Category A Image${game.categoryA?" ("+game.categoryA+")":""}`} value={game.categoryAImage||""} onChange={v=>set("categoryAImage",v)} preset="category" compact={true}/>
            </div>
            <div style={{flex:1}}>
              <ImageUploader label={`Category B Image${game.categoryB?" ("+game.categoryB+")":""}`} value={game.categoryBImage||""} onChange={v=>set("categoryBImage",v)} preset="category" compact={true}/>
            </div>
          </div>
          <div style={{display:"flex",gap:9}}>
            <div style={{flex:1}}>
              <ColorPicker label={`Category A Color${game.categoryA?" ("+game.categoryA+")":""}`} value={game.categoryAColor||"teal"} onChange={v=>set("categoryAColor",v)}/>
            </div>
            <div style={{flex:1}}>
              <ColorPicker label={`Category B Color${game.categoryB?" ("+game.categoryB+")":""}`} value={game.categoryBColor||"pink"} onChange={v=>set("categoryBColor",v)}/>
            </div>
          </div>
          <ImageUploader label="Header Image (shown on home screen & archive)" value={game.headerImage||""} onChange={v=>set("headerImage",v)} preset="header" compact={true}/>
          <div style={{display:"flex",gap:7,marginTop:2}}>
            <button className="btn-adm btn-adm-g" onClick={dftSafe}>Save Draft</button>
            <button className={`btn-adm ${canPublish?"btn-adm-green":""}`} style={!canPublish?{opacity:.5,cursor:"not-allowed"}:{}} onClick={pubSafe}>{game.status==="published"?"✓ Published":"Publish"}</button>
          </div>
        </div>
        <div className="adm-card">
          <h3>Questions</h3>
          <div className={`count-bar ${ok?"ok":"bad"}`}>{qc} questions {!ok?`— need 4–15 to publish`:"— ✓ ready"}</div>
          {(game.questions??[]).map((q,i)=>(
            <div key={q.id}>
              <div
                className={`q-row ${dragQId===q.id?"dragging":""} ${dragOverQId===q.id&&dragQId!==q.id?"drag-over":""}`}
                draggable
                onDragStart={e=>startDrag(e,q.id)}
                onDragOver={e=>overDrag(e,q.id)}
                onDrop={e=>dropDrag(e,q.id)}
                onDragEnd={endDrag}
              >
                <div className="q-drag" title="Drag to reorder">⋮</div>
                <div className="q-num">{i+1}</div>
                <div className="q-inf">
                  <div className="q-txt">{q.itemText}</div>
                  <div className="q-meta">{q.flavorCopy?"flavor ✓":"no flavor"} · {q.imageUrl?(isYouTubeUrl(q.imageUrl)?"video ✓":"image ✓"):"no media"}</div>
                  <span className="q-correct">✓ {q.correctCategory==="A"?game.categoryA:game.categoryB}</span>
                </div>
                <div className="q-actions">
                  <button className="btn-adm btn-adm-g" style={{padding:"4px 10px",fontSize:12}} onClick={()=>{setShowQF(false);setEditQ(editQ?.id===q.id?null:q);}}>{editQ?.id===q.id?"Close":"Edit"}</button>
                  <button className="btn-adm btn-adm-red q-trash" style={{padding:"4px 9px",fontSize:12}} onClick={()=>delQ(q)} title="Delete question">🗑</button>
                </div>
              </div>
              {editQ?.id===q.id&&<QForm key={q.id} initial={editQ} catA={game.categoryA} catB={game.categoryB} onSave={updated=>{updQ(updated);setEditQ(null);}} onCancel={()=>setEditQ(null)}/>}
            </div>
          ))}
          {!showQF&&!editQ&&<button className="btn-adm btn-adm-y" style={{marginTop:9,width:"100%"}} onClick={()=>setShowQF(true)}>+ Add Question</button>}
          {showQF&&!editQ&&<QForm catA={game.categoryA} catB={game.categoryB} onSave={addQ} onCancel={()=>setShowQF(false)}/>}
        </div>
        {!isNew&&game.status!=="published"&&<div style={{textAlign:"center"}}><button className="btn-adm btn-adm-red" onClick={()=>onDelete(game.id)}>Delete game</button></div>}
      </div>
      {toast&&<Toast message={toast} onDone={()=>setToast(null)}/>}
    </div>
  );
}

function QForm({initial,catA,catB,onSave,onCancel}){
  const[q,setQ]=useState(initial||{itemText:"",correctCategory:"A",flavorCopy:"",explanationCopy:"",imageUrl:"",imageAlt:"",imageSource:""});
  const up=(f,v)=>setQ(p=>({...p,[f]:v}));
  return(
    <div className="q-form-box">
      <div className="q-form-title">{initial?"Edit Question":"New Question"}</div>
      <div className="q-form-grid">
        <div className="adm-field"><label>Item Text *</label><input className="adm-input" value={q.itemText} placeholder="e.g. Jumanji" onChange={e=>up("itemText",e.target.value)}/></div>
        <div className="adm-field">
          <label>Correct Category</label>
          <div className="tog-pair">
            <button className={`tog ${q.correctCategory==="A"?"on":""}`} onClick={()=>up("correctCategory","A")}>A: {catA||"Cat A"}</button>
            <button className={`tog ${q.correctCategory==="B"?"on":""}`} onClick={()=>up("correctCategory","B")}>B: {catB||"Cat B"}</button>
          </div>
        </div>
        <div className="adm-field"><label>Flavor Copy</label><textarea className="adm-input adm-ta" value={q.flavorCopy} placeholder="Funny reaction line..." onChange={e=>up("flavorCopy",e.target.value)}/></div>
        <div className="adm-field"><label>Explanation Copy</label><textarea className="adm-input adm-ta" value={q.explanationCopy} placeholder="One factual sentence..." onChange={e=>up("explanationCopy",e.target.value)}/></div>
        <div className="q-form-wide"><ImageUploader label="Reveal Media (image or YouTube link)" value={q.imageUrl||""} onChange={v=>up("imageUrl",v)} preset="question" allowYouTube={true} compact={true}/></div>
        {q.imageUrl&&!isYouTubeUrl(q.imageUrl)&&<div className="adm-field"><label>Alt Text *</label><input className="adm-input" value={q.imageAlt} placeholder="Screen reader description..." onChange={e=>up("imageAlt",e.target.value)}/></div>}
        {q.imageUrl&&<div className="adm-field"><label>Media Source</label><input className="adm-input" value={q.imageSource} placeholder={isYouTubeUrl(q.imageUrl)?"Official music video, lyric video, etc.":"Via Wikimedia Commons"} onChange={e=>up("imageSource",e.target.value)}/></div>}
      </div>
      <div style={{display:"flex",gap:7,marginTop:7}}>
        <button className="btn-adm btn-adm-y" onClick={()=>q.itemText.trim()&&onSave({...q})}>{initial?"Update":"Add"}</button>
        <button className="btn-adm btn-adm-g" onClick={onCancel}>Cancel</button>
      </div>
    </div>
  );
}

function AdminPreview({game,onBack}){
  const dummySound={play:()=>{}};
  const[pr,setPr]=useState({date:game.date,themeTitle:game.themeTitle,totalQuestions:game.questions.length,currentIndex:0,answers:[],score:0,completed:false,startedAt:new Date().toISOString(),completedAt:null});
  const[view,setView]=useState("home");
  const onComplete=final=>{setPr(final);setView("score");};
  return(
    <div className="adm-shell">
      <div className="prev-banner">🎭 Preview Mode — scores not saved</div>
      <div className="adm-hdr"><div className="adm-title">Preview</div><button className="btn-adm btn-adm-g" onClick={onBack}>← Exit Preview</button></div>
      <div style={{maxWidth:500,margin:"0 auto",padding:"14px 18px"}}>
        <style>{styles}</style>
        {view==="home"&&(
          <div className="card" style={{marginTop:8,overflow:"hidden",padding:0}}>
            {game.headerImage&&(
              <div className="game-header-img-wrap" style={{margin:0,borderRadius:"14px 14px 0 0"}}>
                <img src={game.headerImage} alt={game.themeTitle} className="game-header-img" style={{borderRadius:0}} onError={e=>e.target.style.display="none"}/>
              </div>
            )}
            <div style={{padding:"24px 20px"}}>
            <div className="theme-lbl">Today's Theme</div>
            <div className="theme-title">{game.themeTitle}</div>
            <div className="vs-strip"><FitText as="span" className="cat-chip cat-a" min={10} max={13} oneLine={true}>{game.categoryA}</FitText><span className="vs-word">VS</span><FitText as="span" className="cat-chip cat-b" min={10} max={13} oneLine={true}>{game.categoryB}</FitText></div>
            <div className="theme-count">{game.questions.length} questions</div>
            <button className="btn btn-yellow" onClick={()=>setView("game")}>Let's gooo!! →</button>
            </div>
          </div>
        )}
        {view==="game"&&<GameScreen game={game} gameRecord={pr} onComplete={onComplete} onNav={()=>setView("home")} sound={dummySound} isReplay={true}/>}
        {view==="score"&&<ScoreScreen gameRecord={pr} game={game} onNav={()=>setView("home")} sound={dummySound} isReplay={true}/>}
      </div>
    </div>
  );
}

// ============================================================
// ROOT APP
// ============================================================
export default function WhatTheFudgeTrivia(){
  const[view,setView]=useState("home");
  const[adminView,setAdminView]=useState("login");
  const[adminIn,setAdminIn]=useState(false);
  const[editGame,setEditGame]=useState(null);
  const[replayGame,setReplayGame]=useState(null);
  const[replayRecord,setReplayRecord]=useState(null);
  const[toast,setToast]=useState(null);

  // Supabase state
  const[games,setGames]=useState([]);
  const[player,setPlayer]=useState(null);
  const[stats,setStats]=useState({currentStreak:0,longestStreak:0,lastPlayedDate:null,totalPlayed:0,totalCorrect:0,totalQuestions:0,bestCombo:0});
  const[gameRecord,setGameRecord]=useState(null);
  const[loading,setLoading]=useState(true);
  const[error,setError]=useState(null);
  const[authBusy,setAuthBusy]=useState(false);
  const[authMode,setAuthMode]=useState(null);
  const authUserIdRef = useRef(null);

  const sound=useSoundEngine();
  const today=getLocalGameDay();

  const loadAppData = useCallback(async(sessionOverride=null,{recoverAuth=false}={})=>{
    const session = sessionOverride || await authEnsureSession({recover:recoverAuth});
    const p = await dbGetOrCreatePlayer(session?.user);
    if(!p?.id) throw new Error("Player session could not be created.");
    authUserIdRef.current = p?.id || null;
    setPlayer(p);
    const [allGames, playerStats] = await Promise.all([
      dbLoadGames(),
      dbGetStats(p.id)
    ]);
    setGames(allGames);
    setStats(playerStats);
    const todayG = allGames.find(g=>g.date===today&&g.status==="published");
    if(todayG){
      const rec = await dbGetGameRecord(p.id, today);
      setGameRecord(rec);
    } else {
      setGameRecord(null);
    }
  },[today]);

  // Boot and listen for auth session changes
  useEffect(()=>{
    let active = true;
    let authReloadTimer = null;
    const boot = async()=>{
      try {
        setLoading(true);
        setError(null);
        await withTimeout(
          loadAppData(null,{recoverAuth:true}),
          APP_BOOT_TIMEOUT_MS,
          "App boot timed out."
        );
      } catch(e){
        console.error("[boot] first attempt failed", e);
        try{
          clearSupabaseAuthCache();
          await withTimeout(
            loadAppData(null,{recoverAuth:true}),
            APP_BOOT_TIMEOUT_MS,
            "App boot retry timed out."
          );
        }catch(retryError){
          setError("Couldn't connect to server. Check your connection.");
          console.error("[boot] retry failed", retryError);
        }
      } finally {
        if(active) setLoading(false);
      }
    };
    boot();
    const { data:{ subscription } } = authSubscribe((event, session)=>{
      if(!active) return;
      if(event==="TOKEN_REFRESHED"||event==="INITIAL_SESSION") return;
      if(event==="SIGNED_IN" && session?.user?.id===authUserIdRef.current) return;
      clearTimeout(authReloadTimer);
      authReloadTimer = setTimeout(async()=>{
        if(!active) return;
        try{
          setError(null);
          const ensured = session?.user ? session : await authEnsureSession({recover:true});
          await withTimeout(
            loadAppData(ensured,{recoverAuth:true}),
            APP_BOOT_TIMEOUT_MS,
            "Auth reload timed out."
          );
        }catch(e){
          setError("Couldn't connect to server. Check your connection.");
          console.error("[auth change] reload failed", e);
        }
      },0);
    });
    return ()=>{
      active = false;
      clearTimeout(authReloadTimer);
      subscription.unsubscribe();
    };
  },[loadAppData]);

  const todayGame = games.find(g=>g.date===today&&g.status==="published") || null;

  const showToast = m => { setToast(m); setTimeout(()=>setToast(null),2100); };

  const handleCreateAccount = async(email,password) => {
    try{
      setAuthMode("create");
      setAuthBusy(true);
      await authCreatePasswordAccount(email,password);
      showToast("Account created.");
    }catch(e){
      showToast(formatAuthError(e));
    }finally{
      setAuthBusy(false);
      setAuthMode(null);
    }
  };

  const handlePasswordSignIn = async(email,password) => {
    try{
      setAuthMode("password");
      setAuthBusy(true);
      await authSignInWithPassword(email,password);
      showToast("Signed in.");
    }catch(e){
      showToast(formatAuthError(e));
    }finally{
      setAuthBusy(false);
      setAuthMode(null);
    }
  };

  const handleMagicLink = async email => {
    try{
      setAuthMode("magic");
      setAuthBusy(true);
      await authSendMagicLink(email);
      showToast("Magic link sent! Check your email.");
    }catch(e){
      showToast(formatAuthError(e));
    }finally{
      setAuthBusy(false);
      setAuthMode(null);
    }
  };

  const handleSignOut = async() => {
    try{
      setAuthMode("signout");
      setAuthBusy(true);
      await authSignOutToGuest();
      setView("home");
      showToast("Signed out.");
    }catch(e){
      showToast(formatAuthError(e));
    }finally{
      setAuthBusy(false);
      setAuthMode(null);
    }
  };

  // Refresh games from DB (called after admin saves)
  const refreshGames = async() => {
    const allGames = await dbLoadGames();
    setGames(allGames);
  };

  // Admin save
  const handleSave = async(sg) => {
    try {
      if(!localDateFromISO(sg.date)){
        showToast("Pick a valid puzzle date.");
        throw new Error("Pick a valid puzzle date.");
      }
      const conflict = games.find(g=>g.date===sg.date&&g.id!==sg.id);
      if(conflict){
        showToast(`That day already has "${conflict.themeTitle||"another puzzle"}".`);
        throw new Error("That day already has a puzzle.");
      }
      const saved = await dbSaveGame(sg);
      await refreshGames();
      setEditGame(saved);
      showToast("Saved ✓");
      return saved;
    } catch(e){
      const friendly = ["Couldn't import","Pick a valid","That day"].some(prefix=>e?.message?.startsWith(prefix));
      showToast(friendly ? e.message : "Save failed 😬");
      console.error(e);
      throw e;
    }
  };

  // Admin delete
  const handleDel = async(id) => {
    try {
      await dbDeleteGame(id);
      await refreshGames();
      setAdminView("dashboard");
      setEditGame(null);
    } catch(e){ showToast("Delete failed 😬"); }
  };

  // Start game
  const handlePlay = async() => {
    if(!todayGame) return;
    sound.play("click");
    try {
      let activePlayer = player;
      if(!activePlayer){
        const session = await authEnsureSession();
        activePlayer = await dbGetOrCreatePlayer(session?.user);
        setPlayer(activePlayer);
      }
      if(!activePlayer){
        showToast("Still connecting... try again in a sec.");
        return;
      }
      const rec = await dbInitGameRecord(activePlayer.id, today, todayGame.themeTitle, todayGame.questions.length);
      setGameRecord(rec);
      setView("game");
    } catch(e){
      console.error("Start game error:", e);
      showToast("Couldn't start game 😬");
    }
  };

  // Record an answer mid-game
  const handleAnswer = async(date, answers, score) => {
    if(!player) return;
    try { await dbRecordAnswer(player.id, date, answers, score); } catch(e){}
  };

  // Complete game
  const handleComplete = async(finalRec) => {
    if(!player) return;
    setGameRecord(finalRec);
    setView("score");
    try {
      await dbCompleteGame(player.id, finalRec.date, finalRec.answers, finalRec.score, finalRec.totalQuestions);
      const newStats = await dbGetStats(player.id);
      setStats(newStats);
    } catch(e){ console.error("Complete game error:", e); }
  };

  // Replay
  const handleReplay = g => {
    setReplayGame(g);
    setReplayRecord({date:g.date,themeTitle:g.themeTitle,totalQuestions:g.questions.length,currentIndex:0,answers:[],score:0,completed:false,startedAt:new Date().toISOString(),completedAt:null});
    setView("replay");
  };

  // Loading screen
  if(loading) return(
    <>
      <style>{styles}</style>
      <div style={{minHeight:"100vh",background:"var(--yellow)",backgroundImage:"radial-gradient(circle,#1A1A1A 1.2px,transparent 1.2px)",backgroundSize:"26px 26px",display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:16}}>
        <div style={{fontFamily:"'Fredoka One',cursive",fontSize:32,color:"var(--black)"}}>What The Fudge</div>
        <div style={{fontFamily:"'Fredoka One',cursive",fontSize:18,color:"var(--teal-dark)",animation:"pulseFade .8s ease infinite"}}>Loading... 🍬</div>
      </div>
    </>
  );

  if(error) return(
    <>
      <style>{styles}</style>
      <div style={{minHeight:"100vh",background:"var(--yellow)",backgroundImage:"radial-gradient(circle,#1A1A1A 1.2px,transparent 1.2px)",backgroundSize:"26px 26px",display:"flex",alignItems:"center",justifyContent:"center",padding:24}}>
        <div className="card" style={{textAlign:"center",maxWidth:340}}>
          <div style={{fontSize:48,marginBottom:12}}>😬</div>
          <div style={{fontFamily:"'Fredoka One',cursive",fontSize:22,marginBottom:8}}>Connection Error</div>
          <div style={{fontSize:14,fontWeight:700,color:"#666",marginBottom:20}}>{error}</div>
          <button className="btn btn-teal" onClick={()=>window.location.reload()}>Try Again</button>
        </div>
      </div>
    </>
  );

  // Admin branch
  if(view==="admin"){
    if(!adminIn)return <><style>{styles}</style><AdminLogin onLogin={()=>{setAdminIn(true);setAdminView("dashboard");}}/></>;
    if(adminView==="dashboard")return <><style>{styles}</style><AdminDash games={games} onNew={()=>{setEditGame({id:`g-${Date.now()}`,date:"",themeTitle:"",categoryA:"",categoryB:"",status:"draft",questions:[]});setAdminView("editor");}} onEdit={g=>{setEditGame(g);setAdminView("editor");}} onLogout={()=>{setAdminIn(false);setAdminView("login");setView("home");}}/></>;
    if(adminView==="editor")return <><style>{styles}</style><AdminEditor game={editGame} games={games} onSave={handleSave} onDelete={handleDel} onBack={()=>setAdminView("dashboard")}/></>;
  }

  // Player app
  return(
    <>
      <style>{styles}</style>
      <div className="app">
        <div className="hdr">
          <div className="logo">
            <div className="logo-line1"><span className="logo-what">What The</span></div>
            <div className="logo-line2"><span className="logo-fudge">Fudge</span><span className="logo-emoji">🍬</span></div>
            <div className="logo-line3">Trivia</div>
          </div>
          <div className="nav-row">
            <button className="sound-btn" onClick={()=>sound.setMuted(m=>!m)} title={sound.muted?"Unmute":"Mute"}>
              {sound.muted?"🔇":"🔊"}
            </button>
            <button className="nav-btn" style={{background:"linear-gradient(180deg,#5EEAD4,#2DD4BF 60%,#0F9488)",color:"var(--black)",borderColor:"var(--teal-dark)",boxShadow:"0 3px 0 var(--teal-dark)"}} onClick={()=>setView("home")}>Home</button>
            <button className="nav-btn" title={player?.isGuest?"Sign In":(player?.email||"Account")} style={{background:player?.isGuest?"linear-gradient(180deg,#FFF176,#FFE347 60%,#E6C800)":"linear-gradient(180deg,#C084FC,#A855F7 60%,#7E22CE)",color:player?.isGuest?"var(--black)":"white",borderColor:player?.isGuest?"var(--yellow-dark)":"var(--purple-dark)",boxShadow:player?.isGuest?"0 3px 0 var(--yellow-dark)":"0 3px 0 var(--purple-dark)"}} onClick={()=>setView("account")}>
              {player?.isGuest?"Sign In":formatAccountLabel(player?.email)}
            </button>
            <button className="nav-btn" style={{background:"linear-gradient(180deg,#FF85AA,#FF5C8D 60%,#CC3366)",color:"white",borderColor:"var(--pink-dark)",boxShadow:"0 3px 0 var(--pink-dark)"}} onClick={()=>{setView("admin");setAdminView(adminIn?"dashboard":"login");}}><FI name="gear" size={26} style={{marginRight:6}}/>Admin</button>
          </div>
        </div>

        <div className="main">
          {!todayGame&&view==="home"&&(
            <div className="no-game">
              <div style={{fontSize:56,marginBottom:12,filter:"drop-shadow(0 4px 0 rgba(0,0,0,0.15))"}}>🍬</div>
              <div style={{fontFamily:"'Fredoka One',cursive",fontSize:24,marginBottom:6,color:"var(--black)"}}>No game today!</div>
              <div style={{fontSize:13,fontWeight:700,color:"var(--teal-dark)",marginBottom:18}}>Head to Admin to schedule one!</div>
              <button className="btn btn-teal" onClick={()=>{setView("admin");setAdminView(adminIn?"dashboard":"login");}}>Go to Admin →</button>
            </div>
          )}

          {todayGame&&view==="home"&&(
            <HomeScreen game={todayGame} gameRecord={gameRecord} stats={stats}
              onPlay={handlePlay}
              onNav={v=>{sound.play("click");setView(v);}}
            />
          )}

          {view==="game"&&todayGame&&gameRecord&&(
            <GameScreen
              game={todayGame}
              gameRecord={gameRecord}
              onAnswer={handleAnswer}
              onComplete={handleComplete}
              onNav={setView}
              sound={sound}
            />
          )}

          {view==="replay"&&replayGame&&(
            <GameScreen
              game={replayGame}
              gameRecord={replayRecord}
              onAnswer={()=>{}}
              onComplete={final=>{setReplayRecord(final);setView("replay-score");}}
              onNav={v=>{if(v==="archive")setView("archive");else setView(v);}}
              sound={sound}
              isReplay={true}
            />
          )}

          {view==="score"&&gameRecord&&(
            <ScoreScreen gameRecord={gameRecord} game={todayGame} onNav={setView} sound={sound}/>
          )}

          {view==="replay-score"&&replayRecord&&(
              <ScoreScreen
                gameRecord={replayRecord}
                game={replayGame}
                onNav={v=>{if(v==="archive")setView("archive");else setView(v);}}
                sound={sound}
                isReplay={true}
            />
          )}

          {view==="stats"&&<StatsScreen stats={stats} onNav={setView}/>}
          {view==="account"&&<AccountScreenV2 player={player} onNav={setView} onCreateAccount={handleCreateAccount} onPasswordSignIn={handlePasswordSignIn} onMagicLink={handleMagicLink} onSignOut={handleSignOut} authBusy={authBusy} authMode={authMode}/>}

          {view==="archive"&&(
            <ArchiveScreen
              games={games}
              playerId={player?.id}
              onNav={setView}
              onReplay={handleReplay}
            />
          )}
        </div>

        {toast&&<Toast message={toast} onDone={()=>setToast(null)}/>}
      </div>
    </>
  );
}
